{
  "name": "BarFlow AI",
  "description": "Une application complète de gestion de bar (Point de Vente) avec tableau de bord, affichage cuisine et assistant mixologue IA intégré."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum Category {
  COCKTAIL = 'Cocktails',
  BEER = 'Bières',
  WINE = 'Vins',
  SOFT = 'Softs',
  FOOD = 'Snacks'
}

export interface Product {
  id: string;
  name: string;
  price: number;
  category: Category;
  image?: string;
  description?: string;
}

export interface CartItem extends Product {
  quantity: number;
}

export enum OrderStatus {
  PENDING = 'En attente',
  READY = 'Prêt',
  SERVED = 'Servi',
  PAID = 'Payé'
}

export interface Order {
  id: string;
  items: CartItem[];
  total: number;
  status: OrderStatus;
  timestamp: number;
  tableNumber?: number;
}

export interface SalesData {
  name: string;
  value: number;
}

export interface GeneratedRecipe {
  name: string;
  ingredients: string[];
  instructions: string;
  history: string;
}

import { GoogleGenAI, Type } from "@google/genai";
import { GeneratedRecipe } from '../types';

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const generateCocktailRecipe = async (ingredients: string): Promise<GeneratedRecipe> => {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Crée une recette de cocktail unique et délicieuse (et si possible avec un nom amusant) en utilisant principalement ces ingrédients : ${ingredients}. Si les ingrédients sont incohérents, propose quelque chose de créatif quand même.`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            name: { type: Type.STRING },
            ingredients: { 
              type: Type.ARRAY, 
              items: { type: Type.STRING } 
            },
            instructions: { type: Type.STRING },
            history: { type: Type.STRING, description: "Une courte histoire fictive ou réelle amusante sur ce cocktail" }
          },
          required: ["name", "ingredients", "instructions", "history"]
        }
      }
    });

    const text = response.text;
    if (!text) throw new Error("No response from AI");

    return JSON.parse(text) as GeneratedRecipe;
  } catch (error) {
    console.error("Error generating recipe:", error);
    throw error;
  }
};

import React from 'react';
import { Product } from '../types';
import { Plus } from 'lucide-react';

interface ProductCardProps {
  product: Product;
  onAdd: (product: Product) => void;
