import React, { useState, useMemo } from 'react';
import { Product, Category, CartItem } from '../types';
import { INITIAL_MENU } from '../constants';
import { ProductCard } from '../components/ProductCard';
import { Search, ShoppingCart, Trash2, CreditCard, ChevronDown, ChevronUp } from 'lucide-react';

interface POSProps {
  cart: CartItem[];
  addToCart: (product: Product) => void;
  removeFromCart: (productId: string) => void;
  clearCart: () => void;
  placeOrder: (table: number) => void;
}

export const POS: React.FC<POSProps> = ({ cart, addToCart, removeFromCart, clearCart, placeOrder }) => {
  const [selectedCategory, setSelectedCategory] = useState<Category | 'All'>('All');
  const [searchQuery, setSearchQuery] = useState('');
  const [isCartOpen, setIsCartOpen] = useState(false); // For mobile
  const [tableNumber, setTableNumber] = useState<number>(1);

  const filteredProducts = useMemo(() => {
    return INITIAL_MENU.filter(product => {
      const matchesCategory = selectedCategory === 'All' || product.category === selectedCategory;
      const matchesSearch = product.name.toLowerCase().includes(searchQuery.toLowerCase());
      return matchesCategory && matchesSearch;
    });
  }, [selectedCategory, searchQuery]);

  const cartTotal = cart.reduce((sum, item) => sum + (item.price * item.quantity), 0);
  const totalItems = cart.reduce((sum, item) => sum + item.quantity, 0);

  const categories = ['All', ...Object.values(Category)];

  const handlePlaceOrder = () => {
    if (cart.length === 0) return;
    placeOrder(tableNumber);
    setIsCartOpen(false); // Close mobile cart
  };

  return (
    <div className="h-full flex flex-col md:flex-row overflow-hidden bg-slate-950">

      {/* Main Content (Menu) */}
      <div className="flex-1 flex flex-col h-full overflow-hidden relative">
        {/* Header */}
        <div className="p-4 md:p-6 bg-slate-900 border-b border-slate-800 sticky top-0 z-20">
          <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
            <h1 className="text-2xl font-bold text-white">Prise de commande</h1>
            <div className="relative w-full md:w-64">
              <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
              <input 
                type="text" 
                placeholder="Rechercher..." 
                className="w-full bg-slate-800 border-none rounded-full py-2 pl-10 pr-4 text-white focus:ring-2 focus:ring-bar-accent placeholder-slate-500"
                value={searchQuery}
                onChange={(e) => setSearchQuery(e.target.value)}
              />
            </div>
          </div>

          {/* Categories */}
          <div className="flex gap-2 overflow-x-auto mt-4 pb-2 no-scrollbar">
            {categories.map((cat) => (
              <button
                key={cat}
                onClick={() => setSelectedCategory(cat as Category | 'All')}
                className={`px-4 py-2 rounded-full whitespace-nowrap text-sm font-medium transition-colors ${
                  selectedCategory === cat 
                    ? 'bg-bar-accent text-white' 
                    : 'bg-slate-800 text-slate-400 hover:bg-slate-700 hover:text-white'
                }`}
              >
                {cat}
              </button>
            ))}
          </div>
        </div>

        {/* Product Grid */}
        <div className="flex-1 overflow-y-auto p-4 md:p-6 pb-24 md:pb-6">
          <div className="grid grid-cols-2 sm:grid-cols-3 lg:grid-cols-4 gap-4">
            {filteredProducts.map(product => (
              <ProductCard key={product.id} product={product} onAdd={addToCart} />
            ))}
          </div>
        </div>
      </div>

      {/* Cart Sidebar (Desktop: Fixed Right, Mobile: Drawer) */}
      <div className={`
        fixed inset-0 z-40 md:static md:z-0 md:w-96 bg-slate-900 border-l border-slate-800 flex flex-col transition-transform duration-300 transform
        ${isCartOpen ? 'translate-y-0' : 'translate-y-[100%] md:translate-y-0'}
      `}>
         {/* Mobile Handle to Close */}
         <div className="md:hidden flex justify-center pt-2 pb-1" onClick={() => setIsCartOpen(false)}>
            <div className="w-12 h-1.5 bg-slate-700 rounded-full"></div>
         </div>

         <div className="p-4 border-b border-slate-800 flex justify-between items-center bg-slate-900">
           <div className="flex items-center gap-3">
             <h2 className="text-xl font-bold text-white">Commande</h2>
             <span className="bg-bar-accent text-white text-xs font-bold px-2 py-0.5 rounded-full">{totalItems}</span>
           </div>
           {/* Table Selector */}
           <div className="flex items-center gap-2">
             <span className="text-slate-400 text-sm">Table:</span>
             <input 
              type="number" 
              min="1" 
              max="50"
              value={tableNumber}
              onChange={(e) => setTableNumber(parseInt(e.target.value) || 1)}
              className="w-12 bg-slate-800 text-white text-center rounded border border-slate-700 focus:border-bar-accent outline-none"
             />
           </div>
         </div>

         <div className="flex-1 overflow-y-auto p-4 space-y-3">
           {cart.length === 0 ? (
             <div className="h-full flex flex-col items-center justify-center text-slate-500 opacity-50">
               <ShoppingCart size={48} className="mb-2" />
               <p>Le panier est vide</p>
             </div>
           ) : (
             cart.map(item => (
               <div key={item.id} className="flex justify-between items-center bg-slate-800/50 p-3 rounded-lg border border-slate-700">
                 <div className="flex items-center gap-3">
                    <div className="w-6 h-6 flex items-center justify-center bg-bar-accent/20 text-bar-accent text-xs font-bold rounded">
                      {item.quantity}x
                    </div>
                    <div>
                      <p className="text-white font-medium text-sm">{item.name}</p>
                      <p className="text-slate-400 text-xs">{(item.price * item.quantity).toFixed(2)}€</p>
                    </div>
                 </div>
                 <button 
                  onClick={() => removeFromCart(item.id)}
                  className="p-2 text-slate-500 hover:text-red-400 transition-colors"
                 >
                   <Trash2 size={16} />
                 </button>
               </div>
             ))
           )}
         </div>

         <div className="p-4 bg-slate-800/50 border-t border-slate-800">
           <div className="flex justify-between items-center mb-4">
             <span className="text-slate-400">Total</span>
             <span className="text-2xl font-bold text-white">{cartTotal.toFixed(2)}€</span>
           </div>
           <div className="grid grid-cols-2 gap-3">
             <button 
              onClick={clearCart}
              disabled={cart.length === 0}
              className="py-3 px-4 rounded-xl font-bold text-slate-300 border border-slate-600 hover:bg-slate-700 disabled:opacity-50 disabled:cursor-not-allowed transition-colors"
             >
               Annuler
             </button>
             <button 
              onClick={handlePlaceOrder}
              disabled={cart.length === 0}
              className="py-3 px-4 rounded-xl font-bold text-white bg-gradient-to-r from-bar-accent to-pink-600 shadow-lg shadow-bar-accent/25 hover:shadow-bar-accent/40 disabled:opacity-50 disabled:cursor-not-allowed transition-all flex items-center justify-center gap-2"
             >
               <CreditCard size={18} />
               Commander
             </button>
           </div>
         </div>
      </div>

      {/* Mobile Cart Trigger Button */}
      {!isCartOpen && (
        <button 
          onClick={() => setIsCartOpen(true)}
          className="md:hidden fixed bottom-20 left-4 right-4 bg-bar-accent text-white p-4 rounded-xl shadow-2xl flex justify-between items-center z-30 animate-in fade-in slide-in-from-bottom-4"
        >
          <div className="flex items-center gap-2">
            <div className="bg-white/20 w-8 h-8 rounded-full flex items-center justify-center font-bold text-sm">
              {totalItems}
            </div>
            <span className="font-bold">Voir commande</span>
          </div>
          <div className="flex items-center gap-2">
            <span className="font-bold text-lg">{cartTotal.toFixed(2)}€</span>
            <ChevronUp size={20} />
          </div>
        </button>
      )}
    </div>
  );
};

import React from 'react';
import { Order, OrderStatus } from '../types';
import { CheckCircle, Clock, Bell } from 'lucide-react';

interface KitchenProps {
  orders: Order[];
  updateOrderStatus: (orderId: string, status: OrderStatus) => void;
}

export const Kitchen: React.FC<KitchenProps> = ({ orders, updateOrderStatus }) => {
  const activeOrders = orders.filter(o => o.status !== OrderStatus.PAID).sort((a, b) => b.timestamp - a.timestamp);

  const getStatusColor = (status: OrderStatus) => {
    switch (status) {
      case OrderStatus.PENDING: return 'bg-amber-500/20 text-amber-500 border-amber-500/50';
      case OrderStatus.READY: return 'bg-green-500/20 text-green-500 border-green-500/50';
      case OrderStatus.SERVED: return 'bg-blue-500/20 text-blue-500 border-blue-500/50';
      default: return 'bg-slate-700 text-slate-400';
    }
  };

  return (
    <div className="p-4 md:p-8 min-h-full bg-slate-950">
      <div className="flex items-center justify-between mb-8">
        <h1 className="text-3xl font-bold text-white flex items-center gap-3">
          <Bell className="text-bar-accent" />
          Commandes en Cuisine
        </h1>
        <div className="bg-slate-800 px-4 py-2 rounded-lg text-slate-300">
          En cours: <span className="font-bold text-white ml-2">{activeOrders.length}</span>
        </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
        {activeOrders.length === 0 ? (
          <div className="col-span-full flex flex-col items-center justify-center p-12 text-slate-600 border-2 border-dashed border-slate-800 rounded-2xl">
            <CheckCircle size={64} className="mb-4 opacity-50" />
            <p className="text-xl font-medium">Tout est calme en cuisine !</p>
          </div>
        ) : (
          activeOrders.map(order => (
            <div key={order.id} className="bg-slate-900 border border-slate-800 rounded-xl overflow-hidden flex flex-col shadow-lg animate-in fade-in zoom-in-95 duration-200">
              <div className="p-4 bg-slate-800/50 border-b border-slate-800 flex justify-between items-center">
                <div className="flex flex-col">
                  <span className="text-sm text-slate-400">Table</span>
                  <span className="text-xl font-bold text-white">#{order.tableNumber || '?'}</span>
                </div>
                <div className="flex flex-col items-end">
                   <div className="flex items-center gap-1 text-slate-400 text-xs mb-1">
                     <Clock size={12} />
                     {new Date(order.timestamp).toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'})}
                   </div>
                   <span className={`px-2 py-1 rounded text-xs font-bold border ${getStatusColor(order.status)}`}>
                     {order.status}
                   </span>
                </div>
              </div>

              <div className="p-4 flex-1">
                <ul className="space-y-3">
                  {order.items.map((item, idx) => (
                    <li key={idx} className="flex justify-between items-start">
                      <div className="flex gap-3">
                        <span className="bg-slate-700 text-white w-6 h-6 flex items-center justify-center rounded text-sm font-bold flex-shrink-0">
                          {item.quantity}
                        </span>
                        <span className="text-slate-200 font-medium">{item.name}</span>
                      </div>
                    </li>
                  ))}
                </ul>
              </div>

              <div className="p-4 bg-slate-800/30 border-t border-slate-800">
                 {order.status === OrderStatus.PENDING && (
                   <button 
                    onClick={() => updateOrderStatus(order.id, OrderStatus.READY)}
                    className="w-full py-3 bg-amber-600 hover:bg-amber-500 text-white font-bold rounded-lg transition-colors"
                   >
                     Marquer Prêt
                   </button>
                 )}
                 {order.status === OrderStatus.READY && (
                   <button 
                    onClick={() => updateOrderStatus(order.id, OrderStatus.SERVED)}
                    className="w-full py-3 bg-green-600 hover:bg-green-500 text-white font-bold rounded-lg transition-colors"
                   >
                     Marquer Servi
                   </button>
                 )}
                 {order.status === OrderStatus.SERVED && (
                   <button 
                    onClick={() => updateOrderStatus(order.id, OrderStatus.PAID)}
                    className="w-full py-3 bg-blue-600 hover:bg-blue-500 text-white font-bold rounded-lg transition-colors"
                   >
                     Encaisser
                   </button>
                 )}
              </div>
            </div>
          ))
        )}
      </div>
    </div>
  );
};

import React from 'react';
import { MOCK_SALES_DATA } from '../constants';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, Cell } from 'recharts';
import { TrendingUp, DollarSign, Users, Beer } from 'lucide-react';
import { Order } from '../types';

interface DashboardProps {
  orders: Order[];
}

export const Dashboard: React.FC<DashboardProps> = ({ orders }) => {
  const totalRevenue = orders.reduce((sum, order) => sum + order.total, 0);
  const totalOrders = orders.length;
  // Calculate a mock "average ticket"
  const averageTicket = totalOrders > 0 ? totalRevenue / totalOrders : 0;

  const StatCard = ({ icon, title, value, subtext }: any) => (
    <div className="bg-slate-900 border border-slate-800 p-6 rounded-2xl shadow-lg">
      <div className="flex items-start justify-between">
        <div>
          <p className="text-slate-400 text-sm font-medium mb-1">{title}</p>
          <h3 className="text-2xl font-bold text-white">{value}</h3>
          {subtext && <p className="text-green-400 text-xs mt-2 flex items-center gap-1"><TrendingUp size={12} /> {subtext}</p>}
        </div>
        <div className="p-3 bg-slate-800 rounded-xl text-bar-accent">
          {icon}
        </div>
      </div>
    </div>
  );

  return (
    <div className="p-4 md:p-8 min-h-full bg-slate-950">
      <h1 className="text-3xl font-bold text-white mb-8">Tableau de Bord</h1>

      {/* Stats Grid */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6 mb-8">
        <StatCard 
          icon={<DollarSign size={24} />} 
          title="Chiffre d'affaires (Live)" 
          value={`${totalRevenue.toFixed(2)}€`}
          subtext="+12% vs hier"
        />
        <StatCard 
          icon={<Beer size={24} />} 
          title="Commandes" 
          value={totalOrders} 
          subtext="Activité soutenue"
        />
        <StatCard 
          icon={<Users size={24} />} 
          title="Panier Moyen" 
          value={`${averageTicket.toFixed(2)}€`}
        />
        <StatCard 
          icon={<TrendingUp size={24} />} 
          title="Objectif Hebdo" 
          value="75%" 
          subtext="En bonne voie"
        />
      </div>

      {/* Chart */}
      <div className="bg-slate-900 border border-slate-800 rounded-2xl p-6 shadow-lg h-96">
        <h3 className="text-xl font-bold text-white mb-6">Revenus Semaine</h3>
        <ResponsiveContainer width="100%" height="85%">
          <BarChart data={MOCK_SALES_DATA}>
            <CartesianGrid strokeDasharray="3 3" stroke="#334155" vertical={false} />
            <XAxis dataKey="name" stroke="#94a3b8" tick={{fill: '#94a3b8'}} axisLine={false} tickLine={false} />
            <YAxis stroke="#94a3b8" tick={{fill: '#94a3b8'}} axisLine={false} tickLine={false} prefix="€" />
            <Tooltip 
              contentStyle={{ backgroundColor: '#1e293b', border: 'none', borderRadius: '8px', color: '#fff' }}
              cursor={{fill: 'rgba(255,255,255,0.05)'}}
            />
            <Bar dataKey="value" radius={[4, 4, 0, 0]}>
              {MOCK_SALES_DATA.map((entry, index) => (
                <Cell key={`cell-${index}`} fill={index === 4 ? '#e94560' : '#475569'} />
              ))}
            </Bar>
          </BarChart>
        </ResponsiveContainer>
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { generateCocktailRecipe } from '../services/geminiService';
import { GeneratedRecipe } from '../types';
import { Sparkles, Loader2, Wine, ScrollText, History } from 'lucide-react';

export const InventoryAI: React.FC = () => {
  const [ingredients, setIngredients] = useState('');
  const [loading, setLoading] = useState(false);
  const [recipe, setRecipe] = useState<GeneratedRecipe | null>(null);
  const [error, setError] = useState('');

  const handleGenerate = async () => {
    if (!ingredients.trim()) return;
    setLoading(true);
    setError('');
    setRecipe(null);
    try {
      const result = await generateCocktailRecipe(ingredients);
      setRecipe(result);
    } catch (err) {
      setError("Oups, l'IA a un peu trop bu... Réessayez plus tard.");
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="p-4 md:p-8 min-h-full bg-slate-950 flex flex-col items-center overflow-y-auto pb-24 md:pb-8">
      <div className="max-w-3xl w-full">
        <div className="text-center mb-10">
          <div className="inline-flex items-center justify-center p-3 bg-bar-accent/20 rounded-full mb-4">
            <Sparkles className="text-bar-accent w-8 h-8" />
          </div>
          <h1 className="text-3xl md:text-4xl font-bold text-white mb-2">Mixologue IA</h1>
