  const handleDelete = (id: string) => {
    if (confirm('Supprimer cette table ?')) {
      deleteTable(id);
      refreshData();
    }
  };

  const tablesByZone = tables.reduce((acc, table) => {
    if (!acc[table.zone]) acc[table.zone] = [];
    acc[table.zone].push(table);
    return acc;
