  const getStatusColor = (status: OrderStatus) => {
    switch (status) {
      case OrderStatus.PENDING: return 'bg-amber-500/20 text-amber-500 border-amber-500/50';
      case OrderStatus.READY: return 'bg-green-500/20 text-green-500 border-green-500/50';
      case OrderStatus.SERVED: return 'bg-blue-500/20 text-blue-500 border-blue-500/50';
      default: return 'bg-slate-700 text-slate-400';
    }
  };

  return (
    <div className="p-4 md:p-8 h-full overflow-y-auto bg-slate-950">
      <div className="flex items-center justify-between mb-8">
        <h1 className="text-3xl font-bold text-white flex items-center gap-3">
          <Bell className="text-bar-accent" />
          Commandes en Cuisine
        </h1>
        <div className="bg-slate-800 px-4 py-2 rounded-lg text-slate-300">
          En cours: <span className="font-bold text-white ml-2">{activeOrders.length}</span>
        </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6 pb-24 md:pb-0">
        {activeOrders.length === 0 ? (
          <div className="col-span-full flex flex-col items-center justify-center p-12 text-slate-600 border-2 border-dashed border-slate-800 rounded-2xl">
            <CheckCircle size={64} className="mb-4 opacity-50" />
            <p className="text-xl font-medium">Tout est calme en cuisine !</p>
          </div>
        ) : (
          activeOrders.map(order => (
            <div key={order.id} className="bg-slate-900 border border-slate-800 rounded-xl overflow-hidden flex flex-col shadow-lg animate-in fade-in zoom-in-95 duration-200">
              <div className="p-4 bg-slate-800/50 border-b border-slate-800 flex justify-between items-center">
                <div className="flex flex-col">
                  <span className="text-sm text-slate-400">Table</span>
                  <span className="text-xl font-bold text-white">#{order.tableNumber || '?'}</span>
                </div>
                <div className="flex flex-col items-end">
                   <div className="flex items-center gap-1 text-slate-400 text-xs mb-1">
                     <Clock size={12} />
                     {new Date(order.timestamp).toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'})}
                   </div>
                   <span className={`px-2 py-1 rounded text-xs font-bold border ${getStatusColor(order.status)}`}>
                     {order.status}
                   </span>
                </div>
              </div>

              <div className="p-4 flex-1">
                <ul className="space-y-3">
                  {order.items.map((item, idx) => (
                    <li key={idx} className="flex justify-between items-start">
                      <div className="flex gap-3">
                        <span className="bg-slate-700 text-white w-6 h-6 flex items-center justify-center rounded text-sm font-bold flex-shrink-0">
                          {item.quantity}
                        </span>
                        <span className="text-slate-200 font-medium">{item.name}</span>
                      </div>
                    </li>
                  ))}
                </ul>
              </div>

              <div className="p-4 bg-slate-800/30 border-t border-slate-800">
                 {order.status === OrderStatus.PENDING && (
                   <button 
                    onClick={() => updateOrderStatus(order.id, OrderStatus.READY)}
                    className="w-full py-3 bg-amber-600 hover:bg-amber-500 text-white font-bold rounded-lg transition-colors"
                   >
                     Marquer Prêt
                   </button>
                 )}
                 {order.status === OrderStatus.READY && (
                   <button 
                    onClick={() => updateOrderStatus(order.id, OrderStatus.SERVED)}
                    className="w-full py-3 bg-green-600 hover:bg-green-500 text-white font-bold rounded-lg transition-colors"
                   >
                     Marquer Servi
                   </button>
                 )}
                 {order.status === OrderStatus.SERVED && (
                   <button 
                    onClick={() => updateOrderStatus(order.id, OrderStatus.PAID)}
                    className="w-full py-3 bg-blue-600 hover:bg-blue-500 text-white font-bold rounded-lg transition-colors"
                   >
                     Encaisser
                   </button>
                 )}
              </div>
            </div>
          ))
        )}
      </div>
    </div>
  );
};

import React, { useState, useMemo } from 'react';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, Cell } from 'recharts';
import { TrendingUp, DollarSign, Users, Beer } from 'lucide-react';
import { Order } from '../types';

interface DashboardProps {
  orders: Order[];
  currency: string;
}

type Period = 'week' | 'month' | 'year';

export const Dashboard: React.FC<DashboardProps> = ({ orders, currency }) => {
  const [period, setPeriod] = useState<Period>('week');

  const totalRevenue = orders.reduce((sum, order) => sum + order.total, 0);
  const totalOrders = orders.length;
  const averageTicket = totalOrders > 0 ? totalRevenue / totalOrders : 0;

  // Calcul dynamique des données du graphique basé sur les commandes réelles
  const chartData = useMemo(() => {
    const now = new Date();
    let data: { name: string; value: number; sortKey: number }[] = [];

    if (period === 'week') {
      // 7 derniers jours
      const days = ['Dim', 'Lun', 'Mar', 'Mer', 'Jeu', 'Ven', 'Sam'];
      // Initialiser map
      const stats = new Map();
      for (let i = 6; i >= 0; i--) {
        const d = new Date();
        d.setDate(now.getDate() - i);
        const dayName = days[d.getDay()];
        stats.set(dayName, 0);
        // Ajoutons une clé de tri simple pour l'ordre d'affichage si nécessaire, 
        // ici on se base sur l'ordre d'insertion dans le tableau final
        data.push({ name: dayName, value: 0, sortKey: d.getTime() });
      }

      orders.forEach(order => {
        const d = new Date(order.timestamp);
        // Filtre simple: est-ce dans les 7 derniers jours ?
        const diffTime = Math.abs(now.getTime() - d.getTime());
        const diffDays = Math.ceil(diffTime / (1000 * 60 * 60 * 24)); 

        if (diffDays <= 7) {
            const dayName = days[d.getDay()];
            const idx = data.findIndex(i => i.name === dayName);
            if (idx !== -1) data[idx].value += order.total;
        }
      });
    } else if (period === 'month') {
        // 4 dernières semaines (simplifié)
        for (let i = 1; i <= 4; i++) {
           data.push({ name: `Sem ${i}`, value: 0, sortKey: i });
        }
        // Logic de répartition simplifiée
        orders.forEach(order => {
             // Simuler une répartition pour la démo si les dates sont toutes aujourd'hui
             // En prod, utiliser num semaine réelle
             data[3].value += order.total; 
        });
    } else {
        // Année (Mois)
        const months = ['Jan', 'Fév', 'Mar', 'Avr', 'Mai', 'Juin', 'Juil', 'Août', 'Sep', 'Oct', 'Nov', 'Déc'];
        months.forEach((m, i) => data.push({ name: m, value: 0, sortKey: i }));

        orders.forEach(order => {
            const d = new Date(order.timestamp);
            if (d.getFullYear() === now.getFullYear()) {
                data[d.getMonth()].value += order.total;
            }
        });
    }

    return data;
  }, [orders, period]);

  const getPeriodLabel = () => {
    switch (period) {
      case 'month': return 'Revenus Mensuels';
      case 'year': return 'Revenus Annuels';
      default: return 'Revenus Hebdomadaires';
    }
  };

  const StatCard = ({ icon, title, value, subtext }: any) => (
    <div className="bg-slate-900 border border-slate-800 p-6 rounded-2xl shadow-lg">
      <div className="flex items-start justify-between">
        <div>
          <p className="text-slate-400 text-sm font-medium mb-1">{title}</p>
          <h3 className="text-2xl font-bold text-white">{value}</h3>
          {subtext && <p className="text-green-400 text-xs mt-2 flex items-center gap-1"><TrendingUp size={12} /> {subtext}</p>}
        </div>
        <div className="p-3 bg-slate-800 rounded-xl text-bar-accent">
          {icon}
        </div>
      </div>
    </div>
  );

  return (
    <div className="p-4 md:p-8 h-full overflow-y-auto bg-slate-950">
      <h1 className="text-3xl font-bold text-white mb-8">Tableau de Bord</h1>

      {/* Stats Grid */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6 mb-8">
        <StatCard 
          icon={<DollarSign size={24} />} 
          title="Chiffre d'affaires" 
          value={`${totalRevenue.toFixed(2)}${currency}`}
          subtext="Total historique"
        />
        <StatCard 
          icon={<Beer size={24} />} 
          title="Commandes" 
          value={totalOrders} 
          subtext="Enregistrées en DB"
        />
        <StatCard 
          icon={<Users size={24} />} 
          title="Panier Moyen" 
          value={`${averageTicket.toFixed(2)}${currency}`}
        />
        <StatCard 
          icon={<TrendingUp size={24} />} 
          title="Performance" 
          value={totalOrders > 0 ? "Active" : "En attente"} 
          subtext={period === 'week' ? 'Vue 7j' : 'Vue globale'}
        />
      </div>

      {/* Chart */}
      <div className="bg-slate-900 border border-slate-800 rounded-2xl p-6 shadow-lg h-96 mb-24 md:mb-0">
        <div className="flex flex-col sm:flex-row justify-between items-center mb-6 gap-4">
          <h3 className="text-xl font-bold text-white">{getPeriodLabel()}</h3>
          <div className="flex bg-slate-800 p-1 rounded-lg">
            <button
              onClick={() => setPeriod('week')}
              className={`px-3 py-1 rounded-md text-sm font-medium transition-colors ${period === 'week' ? 'bg-bar-accent text-white shadow' : 'text-slate-400 hover:text-white'}`}
            >
              Semaine
            </button>
            <button
              onClick={() => setPeriod('month')}
              className={`px-3 py-1 rounded-md text-sm font-medium transition-colors ${period === 'month' ? 'bg-bar-accent text-white shadow' : 'text-slate-400 hover:text-white'}`}
            >
              Mois
            </button>
            <button
              onClick={() => setPeriod('year')}
              className={`px-3 py-1 rounded-md text-sm font-medium transition-colors ${period === 'year' ? 'bg-bar-accent text-white shadow' : 'text-slate-400 hover:text-white'}`}
            >
              Année
            </button>
          </div>
        </div>

        {totalOrders === 0 ? (
          <div className="h-full flex items-center justify-center text-slate-500">
            <p>Aucune donnée disponible. Passez une commande !</p>
          </div>
        ) : (
          <ResponsiveContainer width="100%" height="80%">
            <BarChart data={chartData}>
              <CartesianGrid strokeDasharray="3 3" stroke="#334155" vertical={false} />
              <XAxis dataKey="name" stroke="#94a3b8" tick={{fill: '#94a3b8'}} axisLine={false} tickLine={false} />
              <YAxis stroke="#94a3b8" tick={{fill: '#94a3b8'}} axisLine={false} tickLine={false} prefix={currency} />
              <Tooltip 
                contentStyle={{ backgroundColor: '#1e293b', border: 'none', borderRadius: '8px', color: '#fff' }}
                cursor={{fill: 'rgba(255,255,255,0.05)'}}
              />
              <Bar dataKey="value" radius={[4, 4, 0, 0]}>
                {chartData.map((entry, index) => (
                  <Cell key={`cell-${index}`} fill={'#e94560'} />
                ))}
              </Bar>
            </BarChart>
          </ResponsiveContainer>
        )}
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { Product, CategoryDef } from '../types';
import { addProduct, deleteProduct } from '../services/db';
import { Plus, Trash2, Search, Package, X } from 'lucide-react';
import { getIconComponent } from '../components/IconRegistry';

interface ProductsPageProps {
  products: Product[];
  categories: CategoryDef[];
  refreshData: () => void;
  currency: string;
}

export const Products: React.FC<ProductsPageProps> = ({ products, categories, refreshData, currency }) => {
  const [searchQuery, setSearchQuery] = useState('');
  const [isModalOpen, setIsModalOpen] = useState(false);

  // Form State
  const [newName, setNewName] = useState('');
  const [newPrice, setNewPrice] = useState('');
  const [newCategory, setNewCategory] = useState('');
  const [newDesc, setNewDesc] = useState('');

  const handleDelete = (id: string) => {
    if (confirm('Êtes-vous sûr de vouloir supprimer ce produit ?')) {
      deleteProduct(id);
      refreshData();
    }
  };

  const handleAddProduct = (e: React.FormEvent) => {
    e.preventDefault();
    if (!newName || !newPrice) return;

    // Use selected category or fallback to first available
    const catToUse = newCategory || (categories.length > 0 ? categories[0].name : 'Divers');

    const newProduct: Product = {
      id: Math.random().toString(36).substr(2, 9),
      name: newName,
      price: parseFloat(newPrice),
      category: catToUse,
      description: newDesc,
      image: `https://picsum.photos/200/200?random=${Date.now()}` // On garde la propriété pour la compatibilité, même si on ne l'affiche plus
    };

    addProduct(newProduct);
    refreshData();
    setIsModalOpen(false);

    // Reset form
    setNewName('');
    setNewPrice('');
    setNewDesc('');
    setNewCategory('');
  };

  const filteredProducts = products.filter(p => 
    p.name.toLowerCase().includes(searchQuery.toLowerCase()) ||
    p.category.toLowerCase().includes(searchQuery.toLowerCase())
  );

  const getCategoryIcon = (catName: string) => {
    const cat = categories.find(c => c.name === catName);
    return cat ? cat.icon : 'Shapes';
  };

  return (
    <div className="p-4 md:p-8 h-full overflow-y-auto bg-slate-950">
      <div className="flex flex-col md:flex-row justify-between items-center mb-8 gap-4">
        <div>
          <h1 className="text-3xl font-bold text-white flex items-center gap-3">
            <Package className="text-bar-accent" />
            Gestion des Produits
          </h1>
          <p className="text-slate-400 mt-1">Gérez votre carte et votre inventaire</p>
        </div>

        <button 
          onClick={() => setIsModalOpen(true)}
          className="bg-bar-accent hover:bg-pink-600 text-white font-bold py-3 px-6 rounded-xl flex items-center gap-2 transition-colors shadow-lg shadow-bar-accent/25"
        >
          <Plus size={20} />
          Nouveau Produit
        </button>
      </div>

      {/* Search Bar */}
      <div className="relative max-w-md mb-6">
        <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
        <input 
          type="text" 
          placeholder="Rechercher un produit..." 
          className="w-full bg-slate-900 border border-slate-800 rounded-xl py-3 pl-10 pr-4 text-white focus:ring-2 focus:ring-bar-accent placeholder-slate-500 outline-none"
          value={searchQuery}
          onChange={(e) => setSearchQuery(e.target.value)}
        />
      </div>

      {/* Products Grid */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6 pb-24 md:pb-0">
        {filteredProducts.map(product => {
          const Icon = getIconComponent(getCategoryIcon(product.category));

          return (
            <div key={product.id} className="bg-slate-900 border border-slate-800 rounded-xl overflow-hidden shadow-lg group flex flex-col h-full">
              <div className="relative h-48 w-full overflow-hidden bg-gradient-to-br from-slate-800 to-slate-700 flex items-center justify-center group-hover:from-slate-700 group-hover:to-slate-600 transition-colors">
                 <Icon className="text-bar-accent w-20 h-20 drop-shadow-lg transform group-hover:scale-110 transition-transform duration-300" />
                 <div className="absolute top-2 right-2 bg-black/60 backdrop-blur-sm text-white text-xs px-2 py-1 rounded">
                   {product.category}
                 </div>
