          <p className="text-slate-400 mt-1">Consultez et réimprimez vos tickets</p>
        </div>

        <div className="flex gap-4 items-center bg-slate-900 p-2 rounded-xl border border-slate-800">
           <div className="text-right px-2">
              <p className="text-xs text-slate-400">Total Affiché</p>
              <p className="font-bold text-white text-lg">
                {filteredOrders.reduce((sum, o) => sum + o.total, 0).toFixed(2)}{currency}
              </p>
           </div>
        </div>
      </div>

      {/* Filters */}
      <div className="bg-slate-900 border border-slate-800 rounded-xl p-4 mb-6 flex flex-col md:flex-row gap-4">
         <div className="relative flex-1">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
            <input 
              type="text" 
              placeholder="Rechercher (Table, Client, ID)..." 
              className="w-full bg-slate-950 border border-slate-800 rounded-lg py-2 pl-10 pr-4 text-white focus:ring-2 focus:ring-bar-accent outline-none"
              value={searchQuery}
              onChange={(e) => setSearchQuery(e.target.value)}
            />
         </div>
         <div className="flex items-center gap-2 overflow-x-auto no-scrollbar">
            <Filter size={18} className="text-slate-400 min-w-[18px]" />
            <button 
              onClick={() => setStatusFilter('ALL')}
              className={`px-3 py-1.5 rounded-lg text-sm font-medium whitespace-nowrap transition-colors ${statusFilter === 'ALL' ? 'bg-bar-accent text-white' : 'bg-slate-800 text-slate-400 hover:text-white'}`}
            >
              Tous
            </button>
            <button 
              onClick={() => setStatusFilter(OrderStatus.PAID)}
              className={`px-3 py-1.5 rounded-lg text-sm font-medium whitespace-nowrap transition-colors ${statusFilter === OrderStatus.PAID ? 'bg-green-600 text-white' : 'bg-slate-800 text-slate-400 hover:text-white'}`}
            >
              Payés
            </button>
            <button 
              onClick={() => setStatusFilter(OrderStatus.PENDING)}
              className={`px-3 py-1.5 rounded-lg text-sm font-medium whitespace-nowrap transition-colors ${statusFilter === OrderStatus.PENDING ? 'bg-amber-600 text-white' : 'bg-slate-800 text-slate-400 hover:text-white'}`}
            >
              En cours
            </button>
         </div>
      </div>

      {/* Table List */}
      <div className="bg-slate-900 border border-slate-800 rounded-xl overflow-hidden flex-1 shadow-lg">
        <div className="overflow-x-auto">
          <table className="w-full text-left text-sm text-slate-400">
            <thead className="bg-slate-800/50 text-slate-200 uppercase font-medium">
              <tr>
                <th className="p-4">ID / Date</th>
                <th className="p-4">Table & Client</th>
                <th className="p-4">Contenu</th>
                <th className="p-4 text-right">Montant</th>
                <th className="p-4">Paiement</th>
                <th className="p-4 text-center">Status</th>
                <th className="p-4 text-center">Actions</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-800">
              {filteredOrders.length === 0 ? (
                <tr>
                   <td colSpan={7} className="p-8 text-center text-slate-500">Aucune commande trouvée pour cette recherche.</td>
                </tr>
              ) : (
                filteredOrders.map(order => (
                  <tr key={order.id} className="hover:bg-slate-800/30 transition-colors">
                    <td className="p-4">
                      <div className="font-mono text-xs text-slate-500 mb-1">#{order.id.slice(0,8)}</div>
                      <div className="text-white flex items-center gap-1">
                        <Calendar size={12} className="text-bar-accent" />
                        {new Date(order.timestamp).toLocaleDateString()}
                      </div>
                      <div className="text-xs ml-4">{new Date(order.timestamp).toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'})}</div>
                    </td>
                    <td className="p-4">
                      <div className="font-bold text-white text-base">Table {order.tableName}</div>
                      {order.clientName && (
                        <div className="text-xs text-blue-400 flex items-center gap-1 mt-1">
                          <ArrowUpRight size={10} /> {order.clientName}
                        </div>
                      )}
                    </td>
                    <td className="p-4 max-w-xs">
                      <div className="flex flex-wrap gap-1">
                        {order.items.slice(0, 3).map((item, i) => (
                           <span key={i} className="bg-slate-800 px-2 py-0.5 rounded text-xs text-slate-300 border border-slate-700">
                             {item.quantity}x {item.name}
                           </span>
                        ))}
                        {order.items.length > 3 && (
                           <span className="text-xs text-slate-500 self-center">+{order.items.length - 3} autres</span>
                        )}
                      </div>
                    </td>
                    <td className="p-4 text-right">
                       <span className="font-bold text-white text-lg">{order.total.toFixed(2)}{currency}</span>
                    </td>
                    <td className="p-4">
                       <div className="flex items-center gap-2">
                          <span className="text-xs font-medium">{order.paymentMethod || '-'}</span>
                       </div>
                    </td>
                    <td className="p-4 text-center">
                       <span className={`px-2 py-1 rounded text-xs font-bold border ${getStatusColor(order.status)}`}>
                         {order.status}
                       </span>
                    </td>
                    <td className="p-4 text-center">
                       <button 
                         onClick={() => handlePrint(order)}
                         className="p-2 bg-slate-800 hover:bg-bar-accent hover:text-white text-slate-400 rounded-lg transition-colors border border-slate-700 hover:border-bar-accent shadow-sm"
                         title="Imprimer Reçu"
                       >
                         <Printer size={18} />
                       </button>
                    </td>
                  </tr>
                ))
              )}
            </tbody>
          </table>
        </div>
      </div>

      {/* Hidden Receipt Component for Printing */}
      {selectedOrder && (
        <div className="fixed top-0 left-0 -left-[9999px] opacity-0 pointer-events-none">
           <Receipt order={selectedOrder} currency={currency} />
        </div>
      )}
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { HashRouter as Router, Routes, Route } from 'react-router-dom';
import { Navbar } from './components/Navbar';
import { POS } from './pages/POS';
import { Kitchen } from './pages/Kitchen';
import { Dashboard } from './pages/Dashboard';
import { Products } from './pages/Products';
import { CategoriesPage } from './pages/CategoriesPage';
import { SettingsPage } from './pages/SettingsPage';
import { TablesPage } from './pages/TablesPage'; 
import { ClientsPage } from './pages/ClientsPage';
import { SalesHistoryPage } from './pages/SalesHistoryPage';
import { CartItem, Product, Order, OrderStatus, CategoryDef, TableDef, Client } from './types';
import { initDB, getProducts, getOrders, insertOrder, updateOrderStatusInDB, getCategories, getTables, getClients, getSetting, saveSetting } from './services/db';
import { Loader2 } from 'lucide-react';

// Helper to generate IDs without external deps
const generateId = () => Math.random().toString(36).substr(2, 9);

const App: React.FC = () => {
  const [isDbReady, setIsDbReady] = useState(false);
  const [cart, setCart] = useState<CartItem[]>([]);
  const [orders, setOrders] = useState<Order[]>([]);
  const [products, setProducts] = useState<Product[]>([]);
  const [categories, setCategories] = useState<CategoryDef[]>([]);
  const [tables, setTables] = useState<TableDef[]>([]);
  const [clients, setClients] = useState<Client[]>([]);
  const [currency, setCurrency] = useState('€');

  useEffect(() => {
    const setup = async () => {
      try {
        await initDB();
        refreshData();
        setIsDbReady(true);
      } catch (e) {
        console.error("Failed to init DB", e);
      }
    };
    setup();
  }, []);

  const refreshData = () => {
     setProducts(getProducts());
     setOrders(getOrders());
     setCategories(getCategories());
     setTables(getTables());
     setClients(getClients());
     setCurrency(getSetting('currency', '€'));
  };

  const updateCurrency = (newSymbol: string) => {
    saveSetting('currency', newSymbol);
    setCurrency(newSymbol);
  };

  const addToCart = (product: Product) => {
    setCart(prev => {
      const existing = prev.find(item => item.id === product.id);
      if (existing) {
        return prev.map(item => 
          item.id === product.id ? { ...item, quantity: item.quantity + 1 } : item
        );
      }
      return [...prev, { ...product, quantity: 1 }];
    });
  };

  const updateCartItemQuantity = (productId: string, newQuantity: number) => {
    if (newQuantity <= 0) {
      removeFromCart(productId);
      return;
    }
    setCart(prev => prev.map(item => 
      item.id === productId ? { ...item, quantity: newQuantity } : item
    ));
  };

  const removeFromCart = (productId: string) => {
    setCart(prev => prev.filter(item => item.id !== productId));
  };

  const clearCart = () => setCart([]);

  const placeOrder = (tableName: string, client?: Client | null) => {
    if (cart.length === 0) return;

    // Essayer de trouver le numéro si le nom est un numéro
    const tableNumber = parseInt(tableName);

    const newOrder: Order = {
      id: generateId(),
      items: [...cart],
      total: cart.reduce((sum, item) => sum + (item.price * item.quantity), 0),
      status: OrderStatus.PENDING,
      timestamp: Date.now(),
      tableNumber: isNaN(tableNumber) ? undefined : tableNumber,
      tableName: tableName,
      clientId: client?.id,
      clientName: client?.name
    };

    // Persistence SQLite
    insertOrder(newOrder);

    // Update local state from DB to be sure
    refreshData();
    clearCart();
  };

  const updateOrderStatus = (orderId: string, status: OrderStatus) => {
    // Persistence SQLite
    updateOrderStatusInDB(orderId, status);
    // Update local state
    setOrders(getOrders());
  };

  if (!isDbReady) {
    return (
      <div className="h-screen w-screen bg-slate-950 flex flex-col items-center justify-center text-white">
        <Loader2 className="animate-spin mb-4 text-bar-accent" size={48} />
        <p>Chargement de la base de données SQLite...</p>
      </div>
    );
  }

  return (
    <Router>
      <div className="flex h-screen bg-slate-950 text-slate-200 font-sans overflow-hidden">
        <Navbar />
        <main className="flex-1 h-full overflow-hidden md:ml-20 lg:ml-64 relative">
          <Routes>
            <Route 
              path="/" 
              element={<Dashboard orders={orders} currency={currency} />} 
            />
            <Route 
              path="/pos" 
              element={
                <POS 
                  products={products}
                  categories={categories}
                  tables={tables}
                  activeOrders={orders}
                  clients={clients}
                  cart={cart} 
                  addToCart={addToCart}
                  updateCartItemQuantity={updateCartItemQuantity}
                  removeFromCart={removeFromCart} 
                  clearCart={clearCart}
                  placeOrder={placeOrder}
                  currency={currency}
                />
              } 
            />
            <Route 
              path="/kitchen" 
              element={
                <Kitchen 
                  orders={orders} 
                  updateOrderStatus={updateOrderStatus} 
                />
              } 
            />
             <Route 
              path="/history" 
              element={
                <SalesHistoryPage 
                  orders={orders} 
                  currency={currency}
                />
              } 
            />
             <Route 
              path="/clients" 
              element={
                <ClientsPage 
                  clients={clients} 
                  refreshData={refreshData} 
                  currency={currency}
                  orders={orders}
                />
              } 
            />
             <Route 
              path="/products" 
              element={
                <Products 
                  products={products} 
                  categories={categories} 
                  refreshData={refreshData} 
                  currency={currency}
                />
              } 
            />
            <Route 
              path="/tables" 
              element={
                <TablesPage 
                  tables={tables}
                  refreshData={refreshData}
                />
              } 
            />
            <Route 
              path="/categories" 
              element={
                <CategoriesPage 
                  categories={categories}
                  refreshData={refreshData}
                />
              } 
            />
            <Route 
              path="/settings" 
              element={
                <SettingsPage 
                  currentCurrency={currency} 
                  onCurrencyChange={updateCurrency} 
                />
              } 
            />
          </Routes>
        </main>
      </div>
    </Router>
  );
};

export default App;

import React, { useState, useMemo } from 'react';
import { Product, CartItem, CategoryDef, TableDef, Order, Client } from '../types';
import { ProductCard } from '../components/ProductCard';
import { getIconComponent } from '../components/IconRegistry';
import { Search, ShoppingCart, Trash2, CreditCard, ChevronUp, Armchair, X, User, UserPlus, Plus, Minus } from 'lucide-react';

interface POSProps {
  products: Product[];
  categories: CategoryDef[];
  tables: TableDef[];
  activeOrders: Order[]; // Pour savoir si les tables sont occupées
  clients: Client[];
  cart: CartItem[];
  addToCart: (product: Product) => void;
  updateCartItemQuantity: (productId: string, quantity: number) => void;
  removeFromCart: (productId: string) => void;
  clearCart: () => void;
  placeOrder: (tableName: string, client?: Client | null) => void;
  currency: string;
}

export const POS: React.FC<POSProps> = ({ 
  products, 
  categories, 
  tables, 
  activeOrders,
  clients,
  cart, 
  addToCart, 
  updateCartItemQuantity,
  removeFromCart, 
  placeOrder,
  currency
}) => {
  const [selectedCategory, setSelectedCategory] = useState<string>('All');
  const [searchQuery, setSearchQuery] = useState('');
  const [isCartOpen, setIsCartOpen] = useState(false);
  const [selectedTable, setSelectedTable] = useState<string>('');
  const [selectedClient, setSelectedClient] = useState<Client | null>(null);
  const [showTableSelector, setShowTableSelector] = useState(false);
  const [showClientSelector, setShowClientSelector] = useState(false);
  const [clientSearch, setClientSearch] = useState('');

  const filteredProducts = useMemo(() => {
    return products.filter(product => {
      const matchesCategory = selectedCategory === 'All' || product.category === selectedCategory;
      const matchesSearch = product.name.toLowerCase().includes(searchQuery.toLowerCase());
      return matchesCategory && matchesSearch;
    });
  }, [selectedCategory, searchQuery, products]);

  const filteredClients = useMemo(() => {
    return clients.filter(c => c.name.toLowerCase().includes(clientSearch.toLowerCase()));
  }, [clients, clientSearch]);

  const cartTotal = cart.reduce((sum, item) => sum + (item.price * item.quantity), 0);
  const totalItems = cart.reduce((sum, item) => sum + item.quantity, 0);

  const handlePlaceOrder = () => {
    if (cart.length === 0) return;
    if (!selectedTable) {
        setShowTableSelector(true);
        return;
    }
    placeOrder(selectedTable, selectedClient);
    setIsCartOpen(false);
    setSelectedTable('');
    setSelectedClient(null);
  };

  const getCategoryIcon = (catName: string) => {
    const cat = categories.find(c => c.name === catName);
    return cat ? cat.icon : 'Shapes';
  };

  // Group tables by zone
  const tablesByZone = useMemo(() => {
    return tables.reduce((acc, table) => {
        if (!acc[table.zone]) acc[table.zone] = [];
        acc[table.zone].push(table);
        return acc;
    }, {} as Record<string, TableDef[]>);
  }, [tables]);

  const isTableOccupied = (tableName: string) => {
      return activeOrders.some(o => o.tableName === tableName && o.status !== 'Payé');
  };

  return (
    <div className="h-full flex flex-col md:flex-row overflow-hidden bg-slate-950">

      {/* Main Content (Menu) */}
      <div className="flex-1 flex flex-col h-full overflow-hidden relative">
        {/* Header */}
        <div className="p-4 md:p-6 bg-slate-900 border-b border-slate-800 sticky top-0 z-20">
          <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
            <h1 className="text-2xl font-bold text-white">Prise de commande</h1>
            <div className="relative w-full md:w-64">
              <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
              <input 
                type="text" 
                placeholder="Rechercher..." 
                className="w-full bg-slate-800 border-none rounded-full py-2 pl-10 pr-4 text-white focus:ring-2 focus:ring-bar-accent placeholder-slate-500"
                value={searchQuery}
                onChange={(e) => setSearchQuery(e.target.value)}
              />
            </div>
          </div>

          {/* Categories */}
          <div className="flex gap-2 overflow-x-auto mt-4 pb-2 no-scrollbar">
            <button
                onClick={() => setSelectedCategory('All')}
                className={`px-4 py-2 rounded-full whitespace-nowrap text-sm font-medium transition-colors ${
                  selectedCategory === 'All' 
                    ? 'bg-bar-accent text-white' 
                    : 'bg-slate-800 text-slate-400 hover:bg-slate-700 hover:text-white'
                }`}
              >
                Tout
              </button>
            {categories.map((cat) => {
              const Icon = getIconComponent(cat.icon);
              return (
                <button
                  key={cat.id}
                  onClick={() => setSelectedCategory(cat.name)}
                  className={`px-4 py-2 rounded-full whitespace-nowrap text-sm font-medium transition-colors flex items-center gap-2 ${
                    selectedCategory === cat.name
                      ? 'bg-bar-accent text-white' 
                      : 'bg-slate-800 text-slate-400 hover:bg-slate-700 hover:text-white'
                  }`}
                >
                  <Icon size={16} />
                  {cat.name}
                </button>
              );
            })}
          </div>
        </div>

        {/* Product Grid */}
        <div className="flex-1 overflow-y-auto p-4 md:p-6 pb-24 md:pb-6">
          <div className="grid grid-cols-2 sm:grid-cols-3 lg:grid-cols-4 gap-4">
            {filteredProducts.map(product => (
              <ProductCard 
                key={product.id} 
                product={product} 
                iconName={getCategoryIcon(product.category)}
                onAdd={addToCart}
                currency={currency}
              />
            ))}
          </div>
        </div>
      </div>

      {/* Cart Sidebar */}
      <div className={`
        fixed inset-0 z-40 md:static md:z-0 md:w-96 bg-slate-900 border-l border-slate-800 flex flex-col transition-transform duration-300 transform
        ${isCartOpen ? 'translate-y-0' : 'translate-y-[100%] md:translate-y-0'}
      `}>
         {/* Mobile Handle */}
         <div className="md:hidden flex justify-center pt-2 pb-1" onClick={() => setIsCartOpen(false)}>
            <div className="w-12 h-1.5 bg-slate-700 rounded-full"></div>
         </div>

         <div className="p-4 border-b border-slate-800 bg-slate-900">
           <div className="flex justify-between items-center mb-4">
             <div className="flex items-center gap-3">
               <h2 className="text-xl font-bold text-white">Commande</h2>
               <span className="bg-bar-accent text-white text-xs font-bold px-2 py-0.5 rounded-full">{totalItems}</span>
             </div>

             <button 
              onClick={() => setShowTableSelector(true)}
              className={`flex items-center gap-2 px-3 py-1.5 rounded-lg text-sm font-medium transition-colors ${
                selectedTable ? 'bg-bar-accent text-white' : 'bg-slate-800 text-slate-400 hover:text-white'
              }`}
             >
               <Armchair size={16} />
               {selectedTable ? `Table ${selectedTable}` : 'Table'}
             </button>
           </div>

           <button 
             onClick={() => setShowClientSelector(true)}
             className={`w-full flex items-center justify-between px-3 py-2 rounded-lg text-sm font-medium transition-colors border ${
               selectedClient ? 'bg-blue-500/10 border-blue-500/30 text-blue-400' : 'bg-slate-800 border-slate-700 text-slate-400 hover:text-white'
             }`}
           >
             <div className="flex items-center gap-2">
                <User size={16} />
                {selectedClient ? selectedClient.name : 'Client invité'}
             </div>
             {selectedClient && <span className="text-xs bg-blue-500 text-white px-2 py-0.5 rounded-full">{selectedClient.loyaltyPoints} pts</span>}
           </button>
         </div>

         <div className="flex-1 overflow-y-auto p-4 space-y-3">
           {cart.length === 0 ? (
             <div className="h-full flex flex-col items-center justify-center text-slate-500 opacity-50">
               <ShoppingCart size={48} className="mb-2" />
               <p>Le panier est vide</p>
             </div>
           ) : (
             cart.map(item => (
               <div key={item.id} className="flex justify-between items-center bg-slate-800/50 p-3 rounded-lg border border-slate-700">
                 <div className="flex items-center gap-3 flex-1">
                   <div className="flex items-center gap-1 bg-slate-900 rounded-lg p-1 border border-slate-700">
                       <button 
                         onClick={() => updateCartItemQuantity(item.id, item.quantity - 1)}
                         className="w-6 h-6 flex items-center justify-center bg-slate-800 hover:bg-slate-700 hover:text-white text-slate-400 rounded transition-colors"
                       >
                         <Minus size={12} />
                       </button>
                       <input 
                         type="number" 
                         value={item.quantity}
                         onChange={(e) => updateCartItemQuantity(item.id, parseInt(e.target.value) || 0)}
                         className="w-8 bg-transparent text-center text-white text-sm font-bold outline-none"
                         min="1"
                       />
                        <button 
                         onClick={() => updateCartItemQuantity(item.id, item.quantity + 1)}
                         className="w-6 h-6 flex items-center justify-center bg-slate-800 hover:bg-slate-700 hover:text-white text-slate-400 rounded transition-colors"
                       >
                         <Plus size={12} />
                       </button>
                   </div>
                   <div className="min-w-0">
                     <p className="text-white font-medium text-sm truncate">{item.name}</p>
                     <p className="text-bar-accent text-xs font-bold">{item.price}{currency}</p>
                   </div>
                 </div>
                 <button 
                   onClick={() => removeFromCart(item.id)}
                   className="text-slate-500 hover:text-red-500 transition-colors p-2 ml-2"
