    while (stmt.step()) {
      const row = stmt.getAsObject();
      clients.push({
        id: row.id,
        name: row.name,
        phone: row.phone,
        email: row.email,
        notes: row.notes,
        loyaltyPoints: row.loyalty_points,
        totalSpent: row.total_spent,
        balance: row.balance || 0,
        lastVisit: row.last_visit
      });
    }
    stmt.free();
    return clients;
  } catch (e) {
    return [];
  }
};

