                                    </div>
                                    <ul className="text-sm text-slate-300 pl-4 border-l-2 border-slate-700">
                                        {order.items.map((item, idx) => (
                                            <li key={idx} className="flex justify-between">
                                                <span>{item.quantity}x {item.name}</span>
                                            </li>
                                        ))}
                                    </ul>
                                </div>
                            ))}
                        </div>
                    )}
                </div>
            </div>
          </div>
      )}
    </div>
  );
};

import React, { useState } from 'react';
import { Order, OrderStatus, PaymentMethod } from '../types';
import { CheckCircle, Clock, Bell, Wallet, CreditCard, Banknote, Smartphone, Calculator, X, User, Printer, ArrowRight } from 'lucide-react';
import { processOrderPayment, updateOrderStatusInDB, getSetting } from '../services/db';
import { Receipt } from '../components/Receipt';

interface KitchenProps {
  orders: Order[];
  updateOrderStatus: (orderId: string, status: OrderStatus) => void;
}

export const Kitchen: React.FC<KitchenProps> = ({ orders, updateOrderStatus }) => {
  const [payingOrder, setPayingOrder] = useState<Order | null>(null);
  const [successPaymentOrder, setSuccessPaymentOrder] = useState<Order | null>(null);
  const activeOrders = orders.filter(o => o.status !== OrderStatus.PAID).sort((a, b) => b.timestamp - a.timestamp);
  const currency = getSetting('currency', '€');

  const getStatusColor = (status: OrderStatus) => {
    switch (status) {
      case OrderStatus.PENDING: return 'bg-amber-500/20 text-amber-500 border-amber-500/50';
      case OrderStatus.READY: return 'bg-green-500/20 text-green-500 border-green-500/50';
      case OrderStatus.SERVED: return 'bg-blue-500/20 text-blue-500 border-blue-500/50';
      default: return 'bg-slate-700 text-slate-400';
    }
  };

  const PaymentModal = () => {
    const [method, setMethod] = useState<PaymentMethod>(PaymentMethod.CASH);
    const [cashGiven, setCashGiven] = useState<string>('');
    const [step, setStep] = useState<'payment' | 'success'>('payment');

    // Safety check
    if (!payingOrder && !successPaymentOrder) return null;

    const changeDue = payingOrder && cashGiven ? parseFloat(cashGiven) - payingOrder.total : 0;

    const handlePayment = () => {
        if (!payingOrder) return;

        // Update DB
        processOrderPayment(payingOrder.id, method, payingOrder.total, payingOrder.clientId);

        // Update UI locally
        updateOrderStatus(payingOrder.id, OrderStatus.PAID);

        // Update local object for receipt and persistence in success view
        const updatedOrder = { ...payingOrder, paymentMethod: method, status: OrderStatus.PAID };
        setSuccessPaymentOrder(updatedOrder);
        setPayingOrder(null); 
        setStep('success'); 
    };

    const handlePrint = () => {
        window.print();
    };

    const handleClose = () => {
        setPayingOrder(null);
        setSuccessPaymentOrder(null);
        setStep('payment');
    };

    return (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/90 backdrop-blur-sm p-4 animate-in fade-in duration-200">
            <div className={`bg-slate-900 border border-slate-800 w-full rounded-2xl shadow-2xl overflow-hidden flex flex-col transition-all max-w-5xl max-h-[95vh]`}>
                <div className="p-4 border-b border-slate-800 flex justify-between items-center bg-slate-900 shrink-0">
                    <h2 className="text-xl font-bold text-white flex items-center gap-2">
                        {step === 'payment' ? <Wallet className="text-bar-accent" /> : <CheckCircle className="text-green-500" />}
                        {step === 'payment' ? `Encaissement Table ${payingOrder?.tableNumber}` : 'Paiement Réussi'}
                    </h2>
                    <button onClick={handleClose} className="text-slate-400 hover:text-white"><X size={24} /></button>
                </div>

                <div className="p-6 overflow-hidden flex-1 flex flex-col">

                    {step === 'payment' && payingOrder ? (
                        <div className="flex flex-col md:flex-row gap-8 h-full overflow-hidden">
                            {/* LEFT: Receipt Preview (Desktop only) */}
                            <div className="hidden md:flex w-[320px] bg-slate-950 rounded-xl border border-slate-800 flex-col shrink-0 overflow-hidden shadow-inner">
                                <div className="p-3 bg-slate-800/50 border-b border-slate-800 text-center">
                                     <span className="text-xs font-bold text-slate-400 uppercase tracking-widest flex items-center justify-center gap-2">
                                        <Printer size={12} /> Aperçu du Ticket
                                     </span>
                                 </div>
                                 <div className="flex-1 overflow-y-auto p-4 flex justify-center bg-white/5 scrollbar-thin scrollbar-thumb-slate-700">
                                     <div className="scale-[0.85] origin-top text-black shadow-xl">
                                         <Receipt order={{...payingOrder, paymentMethod: method, status: OrderStatus.PAID}} currency={currency} />
                                     </div>
                                 </div>
                            </div>

                            {/* RIGHT: Payment Controls */}
                            <div className="flex-1 flex flex-col overflow-y-auto pr-1">
                                <div className="flex justify-between items-center mb-6 bg-slate-800/50 p-4 rounded-xl border border-slate-800 shrink-0">
                                    <span className="text-slate-400 text-lg">Total à payer</span>
                                    <span className="text-4xl font-bold text-white">{payingOrder.total.toFixed(2)}{currency}</span>
                                </div>

                                {/* Method Selection */}
                                <div className="grid grid-cols-2 sm:grid-cols-4 gap-2 mb-6 shrink-0">
                                    <button onClick={() => setMethod(PaymentMethod.CASH)} className={`flex flex-col items-center justify-center p-3 rounded-lg border transition-all ${method === PaymentMethod.CASH ? 'bg-green-600 border-green-500 text-white' : 'bg-slate-800 border-slate-700 text-slate-400 hover:bg-slate-700'}`}>
                                        <Banknote size={24} className="mb-1" />
                                        <span className="text-xs font-bold">Espèces</span>
                                    </button>
                                    <button onClick={() => setMethod(PaymentMethod.MOBILE_MONEY)} className={`flex flex-col items-center justify-center p-3 rounded-lg border transition-all ${method === PaymentMethod.MOBILE_MONEY ? 'bg-orange-600 border-orange-500 text-white' : 'bg-slate-800 border-slate-700 text-slate-400 hover:bg-slate-700'}`}>
                                        <Smartphone size={24} className="mb-1" />
                                        <span className="text-xs font-bold">Mobile</span>
                                    </button>
                                    <button onClick={() => setMethod(PaymentMethod.CARD)} className={`flex flex-col items-center justify-center p-3 rounded-lg border transition-all ${method === PaymentMethod.CARD ? 'bg-blue-600 border-blue-500 text-white' : 'bg-slate-800 border-slate-700 text-slate-400 hover:bg-slate-700'}`}>
                                        <CreditCard size={24} className="mb-1" />
                                        <span className="text-xs font-bold">Carte</span>
                                    </button>
                                    <button onClick={() => setMethod(PaymentMethod.TAB)} disabled={!payingOrder.clientId} className={`flex flex-col items-center justify-center p-3 rounded-lg border transition-all ${method === PaymentMethod.TAB ? 'bg-purple-600 border-purple-500 text-white' : 'bg-slate-800 border-slate-700 text-slate-400 hover:bg-slate-700'} ${!payingOrder.clientId ? 'opacity-50 cursor-not-allowed' : ''}`}>
                                        <User size={24} className="mb-1" />
                                        <span className="text-xs font-bold">Ardoise</span>
                                    </button>
                                </div>

                                {/* Dynamic Content based on Method */}
                                <div className="bg-slate-950 rounded-xl p-4 border border-slate-800 mb-6 min-h-[120px] shrink-0">
                                    {method === PaymentMethod.CASH && (
                                        <div className="space-y-4">
                                            <div>
                                                <label className="block text-slate-400 text-sm mb-1">Montant perçu</label>
                                                <div className="relative">
                                                    <input 
                                                        type="number" 
                                                        value={cashGiven}
                                                        onChange={(e) => setCashGiven(e.target.value)}
                                                        placeholder="Ex: 50"
                                                        className="w-full bg-slate-900 border border-slate-700 rounded-lg p-3 text-white text-lg font-bold focus:border-green-500 outline-none"
                                                        autoFocus
                                                    />
                                                    <span className="absolute right-4 top-1/2 -translate-y-1/2 text-slate-500">{currency}</span>
                                                </div>
                                            </div>
                                            <div className="flex justify-between items-center pt-2 border-t border-slate-800">
                                                <span className="text-slate-400">À rendre</span>
                                                <span className={`text-2xl font-bold ${changeDue < 0 ? 'text-red-500' : 'text-green-500'}`}>
                                                    {Math.max(0, changeDue).toFixed(2)}{currency}
                                                </span>
                                            </div>
                                        </div>
                                    )}

                                    {method === PaymentMethod.MOBILE_MONEY && (
                                        <div className="text-center py-4">
                                            <Smartphone size={48} className="mx-auto text-orange-500 mb-3" />
                                            <p className="text-white font-medium">En attente de confirmation Mobile Money...</p>
                                            <p className="text-sm text-slate-400 mt-1">Vérifiez le terminal ou le téléphone.</p>
                                        </div>
                                    )}

                                    {method === PaymentMethod.TAB && (
                                        <div className="text-center py-2">
                                            <div className="bg-purple-500/10 p-3 rounded-full inline-block mb-2">
                                                <User size={32} className="text-purple-500" />
                                            </div>
                                            <h3 className="text-white font-bold">{payingOrder.clientName}</h3>
                                            <p className="text-slate-400 text-sm mt-1">
                                                Ce montant sera ajouté à l'ardoise du client (dette).
                                            </p>
                                        </div>
                                    )}

                                    {method === PaymentMethod.CARD && (
                                        <div className="text-center py-4">
                                            <CreditCard size={48} className="mx-auto text-blue-500 mb-3" />
                                            <p className="text-white font-medium">Utilisez le TPE pour encaisser.</p>
                                        </div>
                                    )}
                                </div>

                                <div className="flex-1"></div>

                                <button 
                                    onClick={handlePayment}
                                    disabled={method === PaymentMethod.CASH && changeDue < 0}
                                    className="w-full py-4 bg-bar-accent hover:bg-pink-600 disabled:opacity-50 disabled:cursor-not-allowed text-white font-bold rounded-xl shadow-lg shadow-bar-accent/20 transition-all flex items-center justify-center gap-2 shrink-0"
                                >
                                    <CheckCircle size={20} />
                                    Valider l'encaissement
                                </button>
                            </div>
                        </div>
                    ) : (
                        // SUCCESS VIEW
                        <div className="flex flex-col items-center justify-center h-full py-8 space-y-6 animate-in slide-in-from-right duration-300">
                            <div className="w-24 h-24 bg-green-500 rounded-full flex items-center justify-center shadow-lg shadow-green-500/30 animate-in zoom-in duration-500 delay-100">
                                <CheckCircle size={48} className="text-white" />
                            </div>
                            <div className="text-center">
                                <h3 className="text-3xl font-bold text-white mb-2">Paiement Validé !</h3>
                                <p className="text-slate-400 text-lg">Le ticket est prêt à l'impression.</p>
                            </div>

                            <div className="flex flex-col sm:flex-row gap-4 w-full max-w-md mt-4">
                                <button 
                                    onClick={handlePrint}
                                    className="flex-1 py-4 bg-white hover:bg-slate-200 text-slate-900 font-bold rounded-xl shadow-lg flex items-center justify-center gap-2 transition-colors"
                                >
                                    <Printer size={20} />
                                    Imprimer
                                </button>
                                <button 
                                    onClick={handleClose}
                                    className="flex-1 py-4 bg-slate-800 hover:bg-slate-700 text-white font-bold rounded-xl shadow-lg border border-slate-700 flex items-center justify-center gap-2 transition-colors"
                                >
                                    Fermer
                                    <ArrowRight size={20} />
                                </button>
                            </div>

                            {/* Hidden receipt for printing */}
                            <div className="fixed top-0 left-0 -left-[9999px] opacity-0 pointer-events-none">
                                {successPaymentOrder && <Receipt order={successPaymentOrder} currency={currency} />}
                            </div>
                        </div>
                    )}
                </div>
            </div>
        </div>
    );
  };

  return (
    <div className="p-4 md:p-8 h-full overflow-y-auto bg-slate-950">
      <div className="flex items-center justify-between mb-8">
        <h1 className="text-3xl font-bold text-white flex items-center gap-3">
          <Bell className="text-bar-accent" />
          Commandes en Cuisine
        </h1>
        <div className="bg-slate-800 px-4 py-2 rounded-lg text-slate-300">
          En cours: <span className="font-bold text-white ml-2">{activeOrders.length}</span>
        </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6 pb-24 md:pb-0">
        {activeOrders.length === 0 ? (
          <div className="col-span-full flex flex-col items-center justify-center p-12 text-slate-600 border-2 border-dashed border-slate-800 rounded-2xl">
            <CheckCircle size={64} className="mb-4 opacity-50" />
            <p className="text-xl font-medium">Tout est calme en cuisine !</p>
          </div>
        ) : (
          activeOrders.map(order => (
            <div key={order.id} className="bg-slate-900 border border-slate-800 rounded-xl overflow-hidden flex flex-col shadow-lg animate-in fade-in zoom-in-95 duration-200">
              <div className="p-4 bg-slate-800/50 border-b border-slate-800 flex justify-between items-center">
                <div className="flex flex-col">
                  <span className="text-sm text-slate-400">Table</span>
                  <span className="text-xl font-bold text-white">#{order.tableNumber || '?'}</span>
                </div>
                <div className="flex flex-col items-end">
                   <div className="flex items-center gap-1 text-slate-400 text-xs mb-1">
                     <Clock size={12} />
                     {new Date(order.timestamp).toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'})}
                   </div>
                   <span className={`px-2 py-1 rounded text-xs font-bold border ${getStatusColor(order.status)}`}>
                     {order.status}
                   </span>
                </div>
              </div>

              <div className="p-4 flex-1">
                <ul className="space-y-3">
                  {order.items.map((item, idx) => (
                    <li key={idx} className="flex justify-between items-start">
                      <div className="flex gap-3">
                        <span className="bg-slate-700 text-white w-6 h-6 flex items-center justify-center rounded text-sm font-bold flex-shrink-0">
                          {item.quantity}
                        </span>
                        <span className="text-slate-200 font-medium">{item.name}</span>
                      </div>
                    </li>
                  ))}
                </ul>
                {order.clientName && (
                    <div className="mt-4 pt-3 border-t border-slate-800 flex items-center gap-2 text-sm text-blue-400">
                        <User size={14} />
                        Client: <span className="font-bold">{order.clientName}</span>
                    </div>
                )}
              </div>

              <div className="p-4 bg-slate-800/30 border-t border-slate-800">
                 {order.status === OrderStatus.PENDING && (
                   <button 
                    onClick={() => updateOrderStatus(order.id, OrderStatus.READY)}
                    className="w-full py-3 bg-amber-600 hover:bg-amber-500 text-white font-bold rounded-lg transition-colors"
                   >
                     Marquer Prêt
                   </button>
                 )}
                 {order.status === OrderStatus.READY && (
                   <button 
                    onClick={() => updateOrderStatus(order.id, OrderStatus.SERVED)}
                    className="w-full py-3 bg-green-600 hover:bg-green-500 text-white font-bold rounded-lg transition-colors"
                   >
                     Marquer Servi
                   </button>
                 )}
                 {order.status === OrderStatus.SERVED && (
                   <button 
                    onClick={() => setPayingOrder(order)}
                    className="w-full py-3 bg-blue-600 hover:bg-blue-500 text-white font-bold rounded-lg transition-colors flex items-center justify-center gap-2"
                   >
                     <Calculator size={18} />
                     Encaisser
                   </button>
                 )}
              </div>
            </div>
          ))
        )}
      </div>

      {(payingOrder || successPaymentOrder) && <PaymentModal />}
    </div>
  );
};

import React, { useState } from 'react';
import { Client, Order, PaymentMethod } from '../types';
import { addClient, updateClient, deleteClient, updateClientBalance } from '../services/db';
import { Users, Plus, Search, Phone, Mail, Award, Edit2, Trash2, X, History, ShoppingBag, Wallet, AlertCircle } from 'lucide-react';

interface ClientsPageProps {
  clients: Client[];
  refreshData: () => void;
  currency: string;
  orders: Order[];
}

export const ClientsPage: React.FC<ClientsPageProps> = ({ clients, refreshData, currency, orders }) => {
  const [searchQuery, setSearchQuery] = useState('');
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editingClient, setEditingClient] = useState<Client | null>(null);
  const [viewingHistory, setViewingHistory] = useState<Client | null>(null);

  // Balance Modal
  const [balanceModalClient, setBalanceModalClient] = useState<Client | null>(null);
  const [balanceAmount, setBalanceAmount] = useState('');

  // Form State
  const [name, setName] = useState('');
  const [phone, setPhone] = useState('');
  const [email, setEmail] = useState('');
  const [notes, setNotes] = useState('');

  const openModal = (client?: Client) => {
    if (client) {
      setEditingClient(client);
      setName(client.name);
      setPhone(client.phone || '');
      setEmail(client.email || '');
      setNotes(client.notes || '');
    } else {
      setEditingClient(null);
      setName('');
      setPhone('');
      setEmail('');
      setNotes('');
    }
    setIsModalOpen(true);
  };

  const openBalanceModal = (client: Client) => {
    setBalanceModalClient(client);
    setBalanceAmount('');
  };

  const handleBalanceUpdate = () => {
      if (!balanceModalClient || !balanceAmount) return;
      const amount = parseFloat(balanceAmount);
      if (isNaN(amount) || amount === 0) return;

      updateClientBalance(balanceModalClient.id, amount);
      refreshData();
      setBalanceModalClient(null);
  };

  const handleSettleDebt = () => {
      if (!balanceModalClient) return;
      const debt = Math.abs(balanceModalClient.balance);
      updateClientBalance(balanceModalClient.id, debt);
      refreshData();
      setBalanceModalClient(null);
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!name) return;

    if (editingClient) {
      const updated: Client = {
        ...editingClient,
        name,
        phone,
        email,
        notes
      };
      updateClient(updated);
    } else {
      const newClient: Client = {
        id: `cli_${Date.now()}`,
        name,
        phone,
        email,
        notes,
        loyaltyPoints: 0,
        totalSpent: 0,
        balance: 0,
        lastVisit: Date.now()
      };
      addClient(newClient);
    }
    refreshData();
    setIsModalOpen(false);
  };

  const handleDelete = (id: string) => {
    if (confirm('Supprimer ce client ? Ses statistiques seront perdues.')) {
      deleteClient(id);
      refreshData();
    }
  };

  const filteredClients = clients.filter(c => 
    c.name.toLowerCase().includes(searchQuery.toLowerCase()) || 
    c.phone?.includes(searchQuery)
  );

  const getClientOrders = (clientId: string) => {
      return orders.filter(o => o.clientId === clientId).sort((a,b) => b.timestamp - a.timestamp);
  };

  const getClientTabOrders = (clientId: string) => {
      return orders
        .filter(o => o.clientId === clientId && o.paymentMethod === PaymentMethod.TAB)
        .sort((a,b) => b.timestamp - a.timestamp);
  };

  return (
    <div className="p-4 md:p-8 h-full overflow-y-auto bg-slate-950">
      <div className="flex flex-col md:flex-row justify-between items-center mb-8 gap-4">
        <div>
          <h1 className="text-3xl font-bold text-white flex items-center gap-3">
            <Users className="text-bar-accent" />
            Gestion Clients
          </h1>
          <p className="text-slate-400 mt-1">Fidélisation et gestion des ardoises</p>
        </div>

        <button 
          onClick={() => openModal()}
          className="bg-bar-accent hover:bg-pink-600 text-white font-bold py-3 px-6 rounded-xl flex items-center gap-2 transition-colors shadow-lg shadow-bar-accent/25"
        >
          <Plus size={20} />
          Nouveau Client
        </button>
      </div>

      <div className="relative max-w-md mb-6">
        <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
        <input 
          type="text" 
          placeholder="Rechercher par nom ou téléphone..." 
          className="w-full bg-slate-900 border border-slate-800 rounded-xl py-3 pl-10 pr-4 text-white focus:ring-2 focus:ring-bar-accent placeholder-slate-500 outline-none"
          value={searchQuery}
          onChange={(e) => setSearchQuery(e.target.value)}
        />
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6 pb-24 md:pb-0">
        {filteredClients.map(client => (
          <div key={client.id} className="bg-slate-900 border border-slate-800 rounded-xl p-5 shadow-lg group hover:border-slate-700 transition-all flex flex-col">
            <div className="flex justify-between items-start mb-4">
              <div className="w-12 h-12 bg-slate-800 rounded-full flex items-center justify-center text-slate-400 font-bold text-xl border border-slate-700">
                {client.name.charAt(0).toUpperCase()}
              </div>
              <div className="flex gap-2">
                 <button onClick={() => setViewingHistory(client)} className="p-2 text-slate-500 hover:text-white hover:bg-slate-800 rounded-lg transition-colors" title="Historique">
                    <History size={16} />
                 </button>
                 <button onClick={() => openModal(client)} className="p-2 text-slate-500 hover:text-blue-400 hover:bg-blue-500/10 rounded-lg transition-colors" title="Modifier">
                    <Edit2 size={16} />
                 </button>
                 <button onClick={() => handleDelete(client.id)} className="p-2 text-slate-500 hover:text-red-500 hover:bg-red-500/10 rounded-lg transition-colors" title="Supprimer">
                    <Trash2 size={16} />
                 </button>
              </div>
            </div>

            <div className="mb-4">
                <h3 className="text-xl font-bold text-white mb-1 truncate">{client.name}</h3>
                <div className="space-y-1">
                    {client.phone && <p className="text-sm text-slate-400 flex items-center gap-2 truncate"><Phone size={14} /> {client.phone}</p>}
                    {!client.phone && client.email && <p className="text-sm text-slate-400 flex items-center gap-2 truncate"><Mail size={14} /> {client.email}</p>}
                </div>
            </div>

            <div className="grid grid-cols-2 gap-3 mb-4">
              <div className="bg-slate-800/50 rounded-lg p-2 border border-slate-800">
                  <p className="text-xs text-slate-500 mb-1">Fidélité</p>
                  <p className="text-bar-accent font-bold flex items-center gap-1 text-sm">
                    <Award size={14} /> {client.loyaltyPoints} pts
                  </p>
               </div>
               <div className="bg-slate-800/50 rounded-lg p-2 border border-slate-800">
                  <p className="text-xs text-slate-500 mb-1">Total Dépensé</p>
                  <p className="text-white font-bold text-sm">{client.totalSpent.toFixed(2)}{currency}</p>
               </div>
            </div>

            {/* Ardoise Section */}
            <div className={`mt-auto rounded-xl p-3 border ${client.balance < 0 ? 'bg-red-900/10 border-red-500/30 ring-1 ring-red-500/20' : 'bg-slate-800/30 border-slate-800'}`}>
               <div className="flex justify-between items-center mb-3">
                   <div className="flex items-center gap-2">
                      {client.balance < 0 ? <AlertCircle size={16} className="text-red-500" /> : <Wallet size={16} className="text-green-500" />}
                      <span className="text-xs font-bold uppercase text-slate-400">
                          Total Ardoise
                      </span>
                   </div>
                   <span className={`font-bold text-lg ${client.balance < 0 ? 'text-red-500' : 'text-green-500'}`}>
                     {/* On inverse l'affichage : une balance négative est une dette positive */}
                     {(-client.balance).toFixed(2)}{currency}
                   </span>
               </div>

               <button 
                onClick={() => openBalanceModal(client)}
                className={`w-full py-2 rounded-lg text-sm font-bold flex items-center justify-center gap-2 transition-colors ${
                    client.balance < 0 
                        ? 'bg-red-600 hover:bg-red-500 text-white shadow-lg shadow-red-500/20' 
                        : 'bg-slate-700 hover:bg-slate-600 text-white'
                }`}
               >
                 {client.balance < 0 ? 'Régler l\'ardoise' : 'Gérer l\'ardoise'}
               </button>
            </div>
          </div>
        ))}
      </div>

      {/* Add/Edit Modal */}
      {isModalOpen && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/80 backdrop-blur-sm p-4 animate-in fade-in duration-200">
          <div className="bg-slate-900 border border-slate-800 w-full max-w-lg rounded-2xl shadow-2xl p-6 relative">
            <button 
              onClick={() => setIsModalOpen(false)}
              className="absolute top-4 right-4 text-slate-400 hover:text-white"
            >
              <X size={24} />
            </button>
            <h2 className="text-2xl font-bold text-white mb-6">
              {editingClient ? 'Modifier Client' : 'Nouveau Client'}
            </h2>
            <form onSubmit={handleSubmit} className="space-y-4">
              <div>
                <label className="block text-slate-400 text-sm font-medium mb-1">Nom Complet</label>
                <input type="text" required value={name} onChange={e => setName(e.target.value)} className="w-full bg-slate-950 border border-slate-800 rounded-lg p-3 text-white focus:border-bar-accent outline-none" />
              </div>
              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className="block text-slate-400 text-sm font-medium mb-1">Téléphone</label>
                  <input type="tel" value={phone} onChange={e => setPhone(e.target.value)} className="w-full bg-slate-950 border border-slate-800 rounded-lg p-3 text-white focus:border-bar-accent outline-none" />
                </div>
                <div>
                  <label className="block text-slate-400 text-sm font-medium mb-1">Email</label>
                  <input type="email" value={email} onChange={e => setEmail(e.target.value)} className="w-full bg-slate-950 border border-slate-800 rounded-lg p-3 text-white focus:border-bar-accent outline-none" />
                </div>
              </div>
              <div>
                <label className="block text-slate-400 text-sm font-medium mb-1">Notes (Préférences, Allergies...)</label>
                <textarea value={notes} onChange={e => setNotes(e.target.value)} className="w-full bg-slate-950 border border-slate-800 rounded-lg p-3 text-white focus:border-bar-accent outline-none h-24" />
              </div>
              <button type="submit" className="w-full py-3 rounded-xl bg-bar-accent text-white font-bold hover:bg-pink-600 shadow-lg shadow-bar-accent/20">
                {editingClient ? 'Enregistrer' : 'Créer Client'}
              </button>
            </form>
          </div>
        </div>
      )}

      {/* Balance/Debt Modal */}
      {balanceModalClient && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/90 backdrop-blur-sm p-4 animate-in fade-in duration-200">
          <div className="bg-slate-900 border border-slate-800 w-full max-w-md rounded-2xl shadow-2xl overflow-hidden">
            <div className="p-6 bg-slate-800 border-b border-slate-700">
                <div className="flex justify-between items-start mb-2">
                    <h2 className="text-xl font-bold text-white">Gestion Ardoise</h2>
                    <button onClick={() => setBalanceModalClient(null)} className="text-slate-400 hover:text-white"><X size={24} /></button>
                </div>
                <p className="text-slate-400">{balanceModalClient.name}</p>
            </div>

            <div className="p-6">
                {/* Total Ardoise */}
                <div className="flex justify-between items-center mb-6 bg-slate-950 p-4 rounded-xl border border-slate-800">
                    <span className="text-slate-400 font-medium">Total Ardoise</span>
                    <span className={`text-3xl font-bold ${balanceModalClient.balance < 0 ? 'text-red-500' : 'text-green-500'}`}>
                        {(-balanceModalClient.balance).toFixed(2)}{currency}
                    </span>
                </div>

                {/* Ardoise Details */}
                {balanceModalClient.balance < 0 && (
                    <div className="mb-6 bg-slate-950 rounded-xl border border-slate-800 p-4 max-h-40 overflow-y-auto">
                        <h3 className="text-xs font-bold text-slate-500 uppercase mb-3 sticky top-0 bg-slate-950 pb-1 flex items-center gap-2">
                           <AlertCircle size={12} /> Historique des impayés
                        </h3>
                        {getClientTabOrders(balanceModalClient.id).length > 0 ? (
                            <div className="space-y-2">
                                {getClientTabOrders(balanceModalClient.id).map(order => (
                                    <div key={order.id} className="flex justify-between items-center text-sm border-b border-slate-800/50 pb-1 last:border-0">
                                        <div className="flex flex-col">
                                            <span className="text-white">{new Date(order.timestamp).toLocaleDateString()}</span>
                                            <span className="text-xs text-slate-500">{new Date(order.timestamp).toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'})}</span>
                                        </div>
                                        <div className="flex flex-col items-end">
                                            {/* Affichage de la dette en positif */}
                                            <span className="text-red-400 font-bold">{order.total.toFixed(2)}{currency}</span>
                                            <span className="text-[10px] text-slate-600 bg-slate-900 px-1 rounded">#{order.id.slice(0,4)}</span>
                                        </div>
                                    </div>
                                ))}
                            </div>
                        ) : (
                            <p className="text-xs text-slate-500 italic">Aucune commande spécifique trouvée (Dette manuelle ou ancienne).</p>
                        )}
                    </div>
                )}

                {/* Quick Action: Pay Full Debt */}
                {balanceModalClient.balance < 0 && (
                    <button 
                        onClick={handleSettleDebt}
                        className="w-full mb-6 py-3 px-4 bg-green-600 hover:bg-green-500 text-white rounded-xl font-bold flex items-center justify-between group transition-all shadow-lg shadow-green-900/20"
                    >
                        <span>Tout régler (Encaissement)</span>
                        <span className="bg-black/20 px-2 py-1 rounded text-sm group-hover:bg-black/30">
                            {Math.abs(balanceModalClient.balance).toFixed(2)}{currency}
                        </span>
                    </button>
                )}

                {/* Custom Amount */}
                <div className="space-y-2 mb-6">
                    <label className="block text-sm font-medium text-slate-300">
                        {balanceModalClient.balance < 0 ? 'Remboursement partiel ou avance' : 'Ajouter du crédit / Corriger'}
                    </label>
                    <div className="relative">
                        <input 
                            type="number" 
                            step="0.01"
                            value={balanceAmount}
                            onChange={(e) => setBalanceAmount(e.target.value)}
                            placeholder="Saisir montant..." 
                            className="w-full bg-slate-950 border border-slate-700 rounded-xl py-3 pl-4 pr-12 text-white font-bold text-lg focus:border-bar-accent outline-none"
                            autoFocus
                        />
                        <span className="absolute right-4 top-1/2 -translate-y-1/2 text-slate-500 font-bold">{currency}</span>
                    </div>
                </div>

                {/* Projection */}
                {balanceAmount && !isNaN(parseFloat(balanceAmount)) && (
                    <div className="mb-6 flex items-center justify-between text-sm px-2 bg-slate-800/50 p-2 rounded-lg">
                        <span className="text-slate-400">Nouvelle Ardoise estimée:</span>
                        <span className={`font-bold ${(balanceModalClient.balance + parseFloat(balanceAmount)) < 0 ? 'text-red-400' : 'text-green-400'}`}>
                             {/* Affichage inversé */}
                             {(-(balanceModalClient.balance + parseFloat(balanceAmount))).toFixed(2)}{currency}
                        </span>
                    </div>
                )}

                <button 
                    onClick={handleBalanceUpdate}
                    disabled={!balanceAmount}
                    className="w-full py-4 bg-bar-accent hover:bg-pink-600 disabled:opacity-50 disabled:cursor-not-allowed text-white font-bold rounded-xl shadow-lg shadow-bar-accent/20 transition-all flex items-center justify-center gap-2"
                >
                    <Wallet size={20} />
                    Valider la transaction
                </button>
            </div>
          </div>
        </div>
      )}

      {/* History Modal */}
      {viewingHistory && (
          <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/80 backdrop-blur-sm p-4 animate-in fade-in duration-200">
            <div className="bg-slate-900 border border-slate-800 w-full max-w-2xl max-h-[80vh] rounded-2xl shadow-2xl flex flex-col">
                <div className="p-6 border-b border-slate-800 flex justify-between items-center bg-slate-900 rounded-t-2xl">
                    <h2 className="text-2xl font-bold text-white flex items-center gap-2">
                        <ShoppingBag className="text-bar-accent" />
                        Historique - {viewingHistory.name}
                    </h2>
                    <button onClick={() => setViewingHistory(null)} className="text-slate-400 hover:text-white"><X size={24} /></button>
                </div>
                <div className="p-6 overflow-y-auto">
                    {getClientOrders(viewingHistory.id).length === 0 ? (
                        <div className="text-center text-slate-500 py-10">Aucune commande trouvée.</div>
                    ) : (
                        <div className="space-y-4">
                            {getClientOrders(viewingHistory.id).map(order => (
                                <div key={order.id} className="bg-slate-800/50 border border-slate-800 p-4 rounded-xl">
                                    <div className="flex justify-between items-center mb-2">
                                        <div className="text-sm text-slate-400">
                                            {new Date(order.timestamp).toLocaleDateString()} à {new Date(order.timestamp).toLocaleTimeString()}
                                        </div>
                                        <div className="font-bold text-white text-lg">{order.total.toFixed(2)}{currency}</div>
                                    </div>
                                    <div className="flex justify-between items-center mb-2">
                                        <span className="text-xs bg-slate-900 px-2 py-1 rounded text-slate-400">
                                            Paiement: {order.paymentMethod || 'Non spécifié'}
                                        </span>
                                    </div>
                                    <ul className="text-sm text-slate-300 pl-4 border-l-2 border-slate-700">
                                        {order.items.map((item, idx) => (
                                            <li key={idx} className="flex justify-between">
                                                <span>{item.quantity}x {item.name}</span>
                                            </li>
                                        ))}
                                    </ul>
                                </div>
                            ))}
                        </div>
                    )}
                </div>
            </div>
          </div>
      )}
    </div>
  );
};

import React, { useState } from 'react';
import { Client, Order, PaymentMethod } from '../types';
import { addClient, updateClient, deleteClient, updateClientBalance } from '../services/db';
import { Users, Plus, Search, Phone, Mail, Award, Edit2, Trash2, X, History, ShoppingBag, Wallet, AlertCircle, Calculator } from 'lucide-react';

interface ClientsPageProps {
  clients: Client[];
  refreshData: () => void;
  currency: string;
  orders: Order[];
}

export const ClientsPage: React.FC<ClientsPageProps> = ({ clients, refreshData, currency, orders }) => {
  const [searchQuery, setSearchQuery] = useState('');
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editingClient, setEditingClient] = useState<Client | null>(null);
  const [viewingHistory, setViewingHistory] = useState<Client | null>(null);

  // Balance Modal
  const [balanceModalClient, setBalanceModalClient] = useState<Client | null>(null);
  const [balanceAmount, setBalanceAmount] = useState('');

  // Form State
  const [name, setName] = useState('');
  const [phone, setPhone] = useState('');
  const [email, setEmail] = useState('');
  const [notes, setNotes] = useState('');

  const openModal = (client?: Client) => {
    if (client) {
      setEditingClient(client);
      setName(client.name);
      setPhone(client.phone || '');
      setEmail(client.email || '');
      setNotes(client.notes || '');
    } else {
      setEditingClient(null);
      setName('');
      setPhone('');
      setEmail('');
      setNotes('');
    }
    setIsModalOpen(true);
  };

  const openBalanceModal = (client: Client) => {
    setBalanceModalClient(client);
    setBalanceAmount('');
  };

  const handleBalanceUpdate = () => {
      if (!balanceModalClient || !balanceAmount) return;
      const amount = parseFloat(balanceAmount);
      if (isNaN(amount) || amount === 0) return;

      updateClientBalance(balanceModalClient.id, amount);
      refreshData();
      setBalanceModalClient(null);
  };

  const handleSettleDebt = () => {
      if (!balanceModalClient) return;
      const debt = Math.abs(balanceModalClient.balance);
      updateClientBalance(balanceModalClient.id, debt);
      refreshData();
      setBalanceModalClient(null);
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!name) return;

    if (editingClient) {
      const updated: Client = {
        ...editingClient,
        name,
        phone,
        email,
        notes
      };
      updateClient(updated);
    } else {
      const newClient: Client = {
        id: `cli_${Date.now()}`,
        name,
        phone,
        email,
        notes,
        loyaltyPoints: 0,
        totalSpent: 0,
        balance: 0,
        lastVisit: Date.now()
      };
      addClient(newClient);
    }
    refreshData();
    setIsModalOpen(false);
  };

  const handleDelete = (id: string) => {
    if (confirm('Supprimer ce client ? Ses statistiques seront perdues.')) {
      deleteClient(id);
      refreshData();
    }
  };

  const filteredClients = clients.filter(c => 
    c.name.toLowerCase().includes(searchQuery.toLowerCase()) || 
    c.phone?.includes(searchQuery)
  );

  const getClientOrders = (clientId: string) => {
      return orders.filter(o => o.clientId === clientId).sort((a,b) => b.timestamp - a.timestamp);
  };

  const getClientTabOrders = (clientId: string) => {
      return orders
        .filter(o => o.clientId === clientId && o.paymentMethod === PaymentMethod.TAB)
        .sort((a,b) => b.timestamp - a.timestamp);
  };

  // Helper calculation for the modal
  const getClientTabStats = (client: Client) => {
      const tabOrders = getClientTabOrders(client.id);
      const totalTabHistory = tabOrders.reduce((sum, o) => sum + o.total, 0);
      const currentDebt = -client.balance; // Assuming negative balance is debt
      const totalPaid = totalTabHistory - currentDebt;
      return { tabOrders, totalTabHistory, currentDebt, totalPaid };
  };

  return (
    <div className="p-4 md:p-8 h-full overflow-y-auto bg-slate-950">
      <div className="flex flex-col md:flex-row justify-between items-center mb-8 gap-4">
        <div>
          <h1 className="text-3xl font-bold text-white flex items-center gap-3">
            <Users className="text-bar-accent" />
            Gestion Clients
          </h1>
          <p className="text-slate-400 mt-1">Fidélisation et gestion des ardoises</p>
        </div>

        <button 
          onClick={() => openModal()}
          className="bg-bar-accent hover:bg-pink-600 text-white font-bold py-3 px-6 rounded-xl flex items-center gap-2 transition-colors shadow-lg shadow-bar-accent/25"
        >
          <Plus size={20} />
          Nouveau Client
        </button>
      </div>

      <div className="relative max-w-md mb-6">
        <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
        <input 
          type="text" 
          placeholder="Rechercher par nom ou téléphone..." 
          className="w-full bg-slate-900 border border-slate-800 rounded-xl py-3 pl-10 pr-4 text-white focus:ring-2 focus:ring-bar-accent placeholder-slate-500 outline-none"
          value={searchQuery}
          onChange={(e) => setSearchQuery(e.target.value)}
        />
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6 pb-24 md:pb-0">
        {filteredClients.map(client => (
          <div key={client.id} className="bg-slate-900 border border-slate-800 rounded-xl p-5 shadow-lg group hover:border-slate-700 transition-all flex flex-col">
            <div className="flex justify-between items-start mb-4">
              <div className="w-12 h-12 bg-slate-800 rounded-full flex items-center justify-center text-slate-400 font-bold text-xl border border-slate-700">
                {client.name.charAt(0).toUpperCase()}
              </div>
              <div className="flex gap-2">
                 <button onClick={() => setViewingHistory(client)} className="p-2 text-slate-500 hover:text-white hover:bg-slate-800 rounded-lg transition-colors" title="Historique">
                    <History size={16} />
                 </button>
                 <button onClick={() => openModal(client)} className="p-2 text-slate-500 hover:text-blue-400 hover:bg-blue-500/10 rounded-lg transition-colors" title="Modifier">
                    <Edit2 size={16} />
                 </button>
                 <button onClick={() => handleDelete(client.id)} className="p-2 text-slate-500 hover:text-red-500 hover:bg-red-500/10 rounded-lg transition-colors" title="Supprimer">
                    <Trash2 size={16} />
                 </button>
              </div>
            </div>

            <div className="mb-4">
                <h3 className="text-xl font-bold text-white mb-1 truncate">{client.name}</h3>
                <div className="space-y-1">
                    {client.phone && <p className="text-sm text-slate-400 flex items-center gap-2 truncate"><Phone size={14} /> {client.phone}</p>}
                    {!client.phone && client.email && <p className="text-sm text-slate-400 flex items-center gap-2 truncate"><Mail size={14} /> {client.email}</p>}
                </div>
            </div>

            <div className="grid grid-cols-2 gap-3 mb-4">
              <div className="bg-slate-800/50 rounded-lg p-2 border border-slate-800">
                  <p className="text-xs text-slate-500 mb-1">Fidélité</p>
                  <p className="text-bar-accent font-bold flex items-center gap-1 text-sm">
                    <Award size={14} /> {client.loyaltyPoints} pts
                  </p>
               </div>
               <div className="bg-slate-800/50 rounded-lg p-2 border border-slate-800">
                  <p className="text-xs text-slate-500 mb-1">Total Dépensé</p>
                  <p className="text-white font-bold text-sm">{client.totalSpent.toFixed(2)}{currency}</p>
               </div>
            </div>

            {/* Ardoise Section */}
            <div className={`mt-auto rounded-xl p-3 border ${client.balance < 0 ? 'bg-red-900/10 border-red-500/30 ring-1 ring-red-500/20' : 'bg-slate-800/30 border-slate-800'}`}>
               <div className="flex justify-between items-center mb-3">
                   <div className="flex items-center gap-2">
                      {client.balance < 0 ? <AlertCircle size={16} className="text-red-500" /> : <Wallet size={16} className="text-green-500" />}
                      <span className="text-xs font-bold uppercase text-slate-400">
                          Total Ardoise
                      </span>
                   </div>
                   <span className={`font-bold text-lg ${client.balance < 0 ? 'text-red-500' : 'text-green-500'}`}>
                     {/* On inverse l'affichage : une balance négative est une dette positive */}
                     {(-client.balance).toFixed(2)}{currency}
                   </span>
               </div>

               <button 
                onClick={() => openBalanceModal(client)}
                className={`w-full py-2 rounded-lg text-sm font-bold flex items-center justify-center gap-2 transition-colors ${
                    client.balance < 0 
                        ? 'bg-red-600 hover:bg-red-500 text-white shadow-lg shadow-red-500/20' 
                        : 'bg-slate-700 hover:bg-slate-600 text-white'
                }`}
               >
                 {client.balance < 0 ? 'Régler l\'ardoise' : 'Gérer l\'ardoise'}
               </button>
            </div>
          </div>
        ))}
      </div>

      {/* Add/Edit Modal */}
      {isModalOpen && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/80 backdrop-blur-sm p-4 animate-in fade-in duration-200">
          <div className="bg-slate-900 border border-slate-800 w-full max-w-lg rounded-2xl shadow-2xl p-6 relative">
            <button 
              onClick={() => setIsModalOpen(false)}
              className="absolute top-4 right-4 text-slate-400 hover:text-white"
            >
              <X size={24} />
            </button>
            <h2 className="text-2xl font-bold text-white mb-6">
              {editingClient ? 'Modifier Client' : 'Nouveau Client'}
            </h2>
            <form onSubmit={handleSubmit} className="space-y-4">
              <div>
                <label className="block text-slate-400 text-sm font-medium mb-1">Nom Complet</label>
                <input type="text" required value={name} onChange={e => setName(e.target.value)} className="w-full bg-slate-950 border border-slate-800 rounded-lg p-3 text-white focus:border-bar-accent outline-none" />
              </div>
              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className="block text-slate-400 text-sm font-medium mb-1">Téléphone</label>
                  <input type="tel" value={phone} onChange={e => setPhone(e.target.value)} className="w-full bg-slate-950 border border-slate-800 rounded-lg p-3 text-white focus:border-bar-accent outline-none" />
                </div>
                <div>
                  <label className="block text-slate-400 text-sm font-medium mb-1">Email</label>
                  <input type="email" value={email} onChange={e => setEmail(e.target.value)} className="w-full bg-slate-950 border border-slate-800 rounded-lg p-3 text-white focus:border-bar-accent outline-none" />
                </div>
              </div>
              <div>
                <label className="block text-slate-400 text-sm font-medium mb-1">Notes (Préférences, Allergies...)</label>
                <textarea value={notes} onChange={e => setNotes(e.target.value)} className="w-full bg-slate-950 border border-slate-800 rounded-lg p-3 text-white focus:border-bar-accent outline-none h-24" />
              </div>
              <button type="submit" className="w-full py-3 rounded-xl bg-bar-accent text-white font-bold hover:bg-pink-600 shadow-lg shadow-bar-accent/20">
                {editingClient ? 'Enregistrer' : 'Créer Client'}
              </button>
            </form>
          </div>
        </div>
      )}

      {/* Balance/Debt Modal */}
      {balanceModalClient && (() => {
          const { tabOrders, totalTabHistory, currentDebt, totalPaid } = getClientTabStats(balanceModalClient);
          return (
            <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/90 backdrop-blur-sm p-4 animate-in fade-in duration-200">
              <div className="bg-slate-900 border border-slate-800 w-full max-w-md rounded-2xl shadow-2xl overflow-hidden flex flex-col max-h-[90vh]">
                <div className="p-6 bg-slate-800 border-b border-slate-700 shrink-0">
                    <div className="flex justify-between items-start mb-2">
                        <h2 className="text-xl font-bold text-white">Gestion Ardoise</h2>
                        <button onClick={() => setBalanceModalClient(null)} className="text-slate-400 hover:text-white"><X size={24} /></button>
                    </div>
                    <p className="text-slate-400">{balanceModalClient.name}</p>
                </div>

                <div className="p-6 overflow-y-auto">
                    {/* Total Ardoise Display */}
                    <div className="flex justify-between items-center mb-6 bg-slate-950 p-4 rounded-xl border border-slate-800">
                        <span className="text-slate-400 font-medium">Total Ardoise</span>
                        <span className={`text-3xl font-bold ${balanceModalClient.balance < 0 ? 'text-red-500' : 'text-green-500'}`}>
                            {currentDebt.toFixed(2)}{currency}
                        </span>
                    </div>

                    {/* Synchronization / Accounting Block */}
                    {balanceModalClient.balance < 0 && (
                        <div className="bg-slate-800/40 rounded-xl p-4 mb-6 border border-slate-700/50">
                             <h3 className="text-xs font-bold text-slate-400 uppercase mb-3 flex items-center gap-2">
                                <Calculator size={14} /> Détail du calcul (Synchronisation)
                             </h3>
                             <div className="space-y-2 text-sm">
                                <div className="flex justify-between text-slate-300">
                                    <span>Cumul Ventes Ardoise</span>
                                    <span>{totalTabHistory.toFixed(2)}{currency}</span>
                                </div>
                                <div className="flex justify-between text-green-400">
                                    <span>Déjà réglé / Avances</span>
                                    <span>-{totalPaid.toFixed(2)}{currency}</span>
                                </div>
                                <div className="flex justify-between font-bold text-white border-t border-slate-700 pt-2 mt-1">
                                    <span>Reste à payer</span>
                                    <span className="text-red-400">{currentDebt.toFixed(2)}{currency}</span>
                                </div>
                             </div>
                        </div>
                    )}

                    {/* Ardoise History List */}
                    {balanceModalClient.balance < 0 && (
                        <div className="mb-6 bg-slate-950 rounded-xl border border-slate-800 p-4 max-h-40 overflow-y-auto">
                            <h3 className="text-xs font-bold text-slate-500 uppercase mb-3 sticky top-0 bg-slate-950 pb-1 flex items-center gap-2">
                            <AlertCircle size={12} /> Historique des commandes (Preuves)
                            </h3>
                            {tabOrders.length > 0 ? (
                                <div className="space-y-2">
                                    {tabOrders.map(order => (
                                        <div key={order.id} className="flex justify-between items-center text-sm border-b border-slate-800/50 pb-1 last:border-0">
                                            <div className="flex flex-col">
                                                <span className="text-white">{new Date(order.timestamp).toLocaleDateString()}</span>
                                                <span className="text-xs text-slate-500">{new Date(order.timestamp).toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'})}</span>
                                            </div>
                                            <div className="flex flex-col items-end">
                                                <span className="text-red-400 font-bold">{order.total.toFixed(2)}{currency}</span>
                                                <span className="text-[10px] text-slate-600 bg-slate-900 px-1 rounded">#{order.id.slice(0,4)}</span>
                                            </div>
                                        </div>
                                    ))}
                                </div>
                            ) : (
                                <p className="text-xs text-slate-500 italic">Dette manuelle importée ou ancienne.</p>
                            )}
                        </div>
                    )}

                    {/* Quick Action: Pay Full Debt */}
                    {balanceModalClient.balance < 0 && (
                        <button 
                            onClick={handleSettleDebt}
                            className="w-full mb-6 py-3 px-4 bg-green-600 hover:bg-green-500 text-white rounded-xl font-bold flex items-center justify-between group transition-all shadow-lg shadow-green-900/20"
                        >
                            <span>Tout régler (Encaissement)</span>
                            <span className="bg-black/20 px-2 py-1 rounded text-sm group-hover:bg-black/30">
                                {Math.abs(balanceModalClient.balance).toFixed(2)}{currency}
                            </span>
                        </button>
                    )}

                    {/* Custom Amount */}
                    <div className="space-y-2 mb-6">
                        <label className="block text-sm font-medium text-slate-300">
                            {balanceModalClient.balance < 0 ? 'Remboursement partiel' : 'Ajouter du crédit'}
                        </label>
                        <div className="relative">
                            <input 
                                type="number" 
                                step="0.01"
                                value={balanceAmount}
                                onChange={(e) => setBalanceAmount(e.target.value)}
                                placeholder="Saisir montant..." 
                                className="w-full bg-slate-950 border border-slate-700 rounded-xl py-3 pl-4 pr-12 text-white font-bold text-lg focus:border-bar-accent outline-none"
                                autoFocus
                            />
                            <span className="absolute right-4 top-1/2 -translate-y-1/2 text-slate-500 font-bold">{currency}</span>
                        </div>
                    </div>

                    {/* Projection */}
                    {balanceAmount && !isNaN(parseFloat(balanceAmount)) && (
                        <div className="mb-6 flex items-center justify-between text-sm px-2 bg-slate-800/50 p-2 rounded-lg">
                            <span className="text-slate-400">Nouvelle Ardoise estimée:</span>
                            <span className={`font-bold ${(balanceModalClient.balance + parseFloat(balanceAmount)) < 0 ? 'text-red-400' : 'text-green-400'}`}>
                                {(-(balanceModalClient.balance + parseFloat(balanceAmount))).toFixed(2)}{currency}
                            </span>
                        </div>
                    )}

                    <button 
                        onClick={handleBalanceUpdate}
                        disabled={!balanceAmount}
                        className="w-full py-4 bg-bar-accent hover:bg-pink-600 disabled:opacity-50 disabled:cursor-not-allowed text-white font-bold rounded-xl shadow-lg shadow-bar-accent/20 transition-all flex items-center justify-center gap-2"
                    >
                        <Wallet size={20} />
                        Valider la transaction
                    </button>
                </div>
              </div>
            </div>
          );
      })()}

      {/* History Modal */}
      {viewingHistory && (
          <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/80 backdrop-blur-sm p-4 animate-in fade-in duration-200">
            <div className="bg-slate-900 border border-slate-800 w-full max-w-2xl max-h-[80vh] rounded-2xl shadow-2xl flex flex-col">
                <div className="p-6 border-b border-slate-800 flex justify-between items-center bg-slate-900 rounded-t-2xl">
                    <h2 className="text-2xl font-bold text-white flex items-center gap-2">
                        <ShoppingBag className="text-bar-accent" />
                        Historique - {viewingHistory.name}
                    </h2>
                    <button onClick={() => setViewingHistory(null)} className="text-slate-400 hover:text-white"><X size={24} /></button>
                </div>
                <div className="p-6 overflow-y-auto">
                    {getClientOrders(viewingHistory.id).length === 0 ? (
                        <div className="text-center text-slate-500 py-10">Aucune commande trouvée.</div>
                    ) : (
                        <div className="space-y-4">
                            {getClientOrders(viewingHistory.id).map(order => (
                                <div key={order.id} className="bg-slate-800/50 border border-slate-800 p-4 rounded-xl">
                                    <div className="flex justify-between items-center mb-2">
                                        <div className="text-sm text-slate-400">
                                            {new Date(order.timestamp).toLocaleDateString()} à {new Date(order.timestamp).toLocaleTimeString()}
                                        </div>
                                        <div className="font-bold text-white text-lg">{order.total.toFixed(2)}{currency}</div>
                                    </div>
                                    <div className="flex justify-between items-center mb-2">
                                        <span className="text-xs bg-slate-900 px-2 py-1 rounded text-slate-400">
                                            Paiement: {order.paymentMethod || 'Non spécifié'}
                                        </span>
                                    </div>
                                    <ul className="text-sm text-slate-300 pl-4 border-l-2 border-slate-700">
                                        {order.items.map((item, idx) => (
                                            <li key={idx} className="flex justify-between">
                                                <span>{item.quantity}x {item.name}</span>
                                            </li>
                                        ))}
                                    </ul>
                                </div>
                            ))}
                        </div>
                    )}
                </div>
            </div>
          </div>
      )}
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { HashRouter as Router, Routes, Route } from 'react-router-dom';
import { Navbar } from './components/Navbar';
import { POS } from './pages/POS';
import { Kitchen } from './pages/Kitchen';
import { Dashboard } from './pages/Dashboard';
import { Products } from './pages/Products';
import { CategoriesPage } from './pages/CategoriesPage';
import { SettingsPage } from './pages/SettingsPage';
import { TablesPage } from './pages/TablesPage'; 
import { ClientsPage } from './pages/ClientsPage';
import { SalesHistoryPage } from './pages/SalesHistoryPage';
import { CartItem, Product, Order, OrderStatus, CategoryDef, TableDef, Client } from './types';
import { initDB, getProducts, getOrders, insertOrder, updateOrderStatusInDB, getCategories, getTables, getClients, getSetting, saveSetting } from './services/db';
import { Loader2 } from 'lucide-react';

// Helper to generate IDs without external deps
const generateId = () => Math.random().toString(36).substr(2, 9);

const App: React.FC = () => {
  const [isDbReady, setIsDbReady] = useState(false);
  const [cart, setCart] = useState<CartItem[]>([]);
  const [orders, setOrders] = useState<Order[]>([]);
  const [products, setProducts] = useState<Product[]>([]);
  const [categories, setCategories] = useState<CategoryDef[]>([]);
  const [tables, setTables] = useState<TableDef[]>([]);
  const [clients, setClients] = useState<Client[]>([]);
  const [currency, setCurrency] = useState('€');

  useEffect(() => {
    const setup = async () => {
      try {
        await initDB();
        refreshData();
        setIsDbReady(true);
      } catch (e) {
        console.error("Failed to init DB", e);
      }
    };
    setup();
  }, []);

  const refreshData = () => {
     setProducts(getProducts());
     setOrders(getOrders());
     setCategories(getCategories());
     setTables(getTables());
     setClients(getClients());
     setCurrency(getSetting('currency', '€'));
  };

  const updateCurrency = (newSymbol: string) => {
    saveSetting('currency', newSymbol);
    setCurrency(newSymbol);
  };

  const addToCart = (product: Product) => {
    setCart(prev => {
      const existing = prev.find(item => item.id === product.id);
      if (existing) {
        return prev.map(item => 
          item.id === product.id ? { ...item, quantity: item.quantity + 1 } : item
        );
      }
      return [...prev, { ...product, quantity: 1 }];
    });
  };

  const updateCartItemQuantity = (productId: string, newQuantity: number) => {
    if (newQuantity <= 0) {
      removeFromCart(productId);
      return;
    }
    setCart(prev => prev.map(item => 
      item.id === productId ? { ...item, quantity: newQuantity } : item
    ));
  };

  const removeFromCart = (productId: string) => {
    setCart(prev => prev.filter(item => item.id !== productId));
  };

  const clearCart = () => setCart([]);

  const placeOrder = (tableName: string, client?: Client | null) => {
    if (cart.length === 0) return;

    // Essayer de trouver le numéro si le nom est un numéro
    const tableNumber = parseInt(tableName);

    const newOrder: Order = {
      id: generateId(),
      items: [...cart],
      total: cart.reduce((sum, item) => sum + (item.price * item.quantity), 0),
      status: OrderStatus.PENDING,
      timestamp: Date.now(),
      tableNumber: isNaN(tableNumber) ? undefined : tableNumber,
      tableName: tableName,
      clientId: client?.id,
      clientName: client?.name
    };

    // Persistence SQLite
    insertOrder(newOrder);

    // Update local state from DB to be sure
    refreshData();
    clearCart();
  };

  const updateOrderStatus = (orderId: string, status: OrderStatus) => {
    // Persistence SQLite
    updateOrderStatusInDB(orderId, status);
    // Update local state
    setOrders(getOrders());
  };

  if (!isDbReady) {
    return (
      <div className="h-screen w-screen bg-slate-950 flex flex-col items-center justify-center text-white">
        <Loader2 className="animate-spin mb-4 text-bar-accent" size={48} />
        <p>Chargement de la base de données SQLite...</p>
      </div>
    );
  }

  return (
    <Router>
      <div className="flex h-screen bg-slate-950 text-slate-200 font-sans overflow-hidden">
        <Navbar />
        <main className="flex-1 h-full overflow-hidden md:ml-20 lg:ml-64 relative">
          <Routes>
            <Route 
              path="/" 
              element={<Dashboard orders={orders} currency={currency} />} 
            />
            <Route 
              path="/pos" 
              element={
                <POS 
                  products={products}
                  categories={categories}
                  tables={tables}
                  activeOrders={orders}
                  clients={clients}
                  cart={cart} 
                  addToCart={addToCart}
                  updateCartItemQuantity={updateCartItemQuantity}
                  removeFromCart={removeFromCart} 
                  clearCart={clearCart}
                  placeOrder={placeOrder}
                  currency={currency}
                />
              } 
            />
            <Route 
              path="/kitchen" 
              element={
                <Kitchen 
                  orders={orders} 
                  updateOrderStatus={updateOrderStatus} 
                  clients={clients}
                />
              } 
            />
             <Route 
              path="/history" 
              element={
                <SalesHistoryPage 
                  orders={orders} 
                  currency={currency}
                />
              } 
            />
             <Route 
              path="/clients" 
              element={
                <ClientsPage 
                  clients={clients} 
                  refreshData={refreshData} 
                  currency={currency}
                  orders={orders}
                />
              } 
            />
             <Route 
              path="/products" 
              element={
                <Products 
                  products={products} 
                  categories={categories} 
                  refreshData={refreshData} 
                  currency={currency}
                />
              } 
            />
            <Route 
              path="/tables" 
              element={
                <TablesPage 
                  tables={tables}
                  refreshData={refreshData}
                />
              } 
            />
            <Route 
              path="/categories" 
              element={
                <CategoriesPage 
                  categories={categories}
                  refreshData={refreshData}
                />
              } 
            />
            <Route 
              path="/settings" 
              element={
                <SettingsPage 
                  currentCurrency={currency} 
                  onCurrencyChange={updateCurrency} 
                />
              } 
            />
          </Routes>
        </main>
      </div>
    </Router>
  );
};

export default App;

import React, { useState } from 'react';
import { Order, OrderStatus, PaymentMethod, Client } from '../types';
import { CheckCircle, Clock, Bell, Wallet, CreditCard, Banknote, Smartphone, Calculator, X, User, Printer, ArrowRight, ArrowDown } from 'lucide-react';
import { processOrderPayment, updateOrderStatusInDB, getSetting } from '../services/db';
import { Receipt } from '../components/Receipt';

interface KitchenProps {
  orders: Order[];
  updateOrderStatus: (orderId: string, status: OrderStatus) => void;
  clients: Client[];
}

export const Kitchen: React.FC<KitchenProps> = ({ orders, updateOrderStatus, clients }) => {
  const [payingOrder, setPayingOrder] = useState<Order | null>(null);
  const [successPaymentOrder, setSuccessPaymentOrder] = useState<Order | null>(null);
  const activeOrders = orders.filter(o => o.status !== OrderStatus.PAID).sort((a, b) => b.timestamp - a.timestamp);
  const currency = getSetting('currency', '€');

  const getStatusColor = (status: OrderStatus) => {
    switch (status) {
      case OrderStatus.PENDING: return 'bg-amber-500/20 text-amber-500 border-amber-500/50';
      case OrderStatus.READY: return 'bg-green-500/20 text-green-500 border-green-500/50';
      case OrderStatus.SERVED: return 'bg-blue-500/20 text-blue-500 border-blue-500/50';
      default: return 'bg-slate-700 text-slate-400';
    }
  };

  const PaymentModal = () => {
    const [method, setMethod] = useState<PaymentMethod>(PaymentMethod.CASH);
    const [cashGiven, setCashGiven] = useState<string>('');
    const [step, setStep] = useState<'payment' | 'success'>('payment');

    // Safety check
    if (!payingOrder && !successPaymentOrder) return null;

    const changeDue = payingOrder && cashGiven ? parseFloat(cashGiven) - payingOrder.total : 0;

    // Find client for Tab calculation
    const currentClient = payingOrder ? clients.find(c => c.id === payingOrder.clientId) : null;

    const handlePayment = () => {
        if (!payingOrder) return;

        // Update DB
        processOrderPayment(payingOrder.id, method, payingOrder.total, payingOrder.clientId);

        // Update UI locally
        updateOrderStatus(payingOrder.id, OrderStatus.PAID);

        // Update local object for receipt and persistence in success view
        const updatedOrder = { ...payingOrder, paymentMethod: method, status: OrderStatus.PAID };
        setSuccessPaymentOrder(updatedOrder);
        setPayingOrder(null); 
        setStep('success'); 
    };

    const handlePrint = () => {
        window.print();
    };

    const handleClose = () => {
        setPayingOrder(null);
        setSuccessPaymentOrder(null);
        setStep('payment');
    };

    return (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/90 backdrop-blur-sm p-4 animate-in fade-in duration-200">
            <div className={`bg-slate-900 border border-slate-800 w-full rounded-2xl shadow-2xl overflow-hidden flex flex-col transition-all max-w-5xl max-h-[95vh]`}>
                <div className="p-4 border-b border-slate-800 flex justify-between items-center bg-slate-900 shrink-0">
                    <h2 className="text-xl font-bold text-white flex items-center gap-2">
                        {step === 'payment' ? <Wallet className="text-bar-accent" /> : <CheckCircle className="text-green-500" />}
                        {step === 'payment' ? `Encaissement Table ${payingOrder?.tableNumber}` : 'Paiement Réussi'}
